     1→/**
     2→ * @module MediaSession
     3→ *
     4→ * The top-level coordinator for a single live phone call at the media layer.
     5→ *
     6→ * ## Purpose
     7→ * `MediaSession` is the single object that owns and orchestrates every
     8→ * component required to run one live conversation:
     9→ *
    10→ * - `ConversationRuntime`     — low-level call state machine
    11→ * - `ConversationOrchestrator` — turn scheduling and barge-in logic
    12→ * - `IAudioEngine`            — inbound/outbound audio pipelines
    13→ * - `IRealtimeProviderSession`— abstract AI provider session
    14→ * - `MediaCoordinator`        — wires the above into a coherent lifecycle
    15→ *
    16→ * `MediaSession` contains NO transport logic, NO Exotel logic, NO OpenAI
    17→ * imports, NO WebSocket, and NO HTTP. Every concern below the media
    18→ * coordination layer is accessed exclusively through the injected
    19→ * `MediaSessionContext`.
    20→ *
    21→ * ## Ownership
    22→ * One `MediaSession` is created per inbound or outbound call by
    23→ * `MediaSessionFactory`. The owner is responsible for calling `destroy()`
    24→ * when the call ends, regardless of success or failure.
    25→ *
    26→ * ## Thread Safety
    27→ * Lifecycle methods are async and must be awaited sequentially by the owner.
    28→ * Concurrent calls to lifecycle methods on the same instance produce
    29→ * undefined behaviour. `MediaSession` does not acquire locks internally.
    30→ *
    31→ * ## Lifecycle
    32→ * ```
    33→ * createMediaSession()
    34→ *   └─► initialize()     — CREATED → INITIALIZING → READY
    35→ *         └─► start()    — READY → ACTIVE (conversation flowing)
    36→ *               ├─► pause(reason)           — ACTIVE → PAUSED
    37→ *               │     └─► resume()          — PAUSED → ACTIVE
    38→ *               ├─► signalInterruption(now) — ACTIVE → INTERRUPTED → ACTIVE
    39→ *               └─► complete(reason)        — ACTIVE | PAUSED → COMPLETING → COMPLETED
    40→ *
    41→ * Any state ──► destroy()   — COMPLETED | FAILED → DESTROYED
    42→ * ```
    43→ */
    44→
    45→import type { MediaSessionContext } from './MediaSessionContext.js';
    46→import type { AudioChunk } from '../audio-engine/AudioChunk.js';
    47→import {
    48→  MediaSessionState,
    49→  MEDIA_VALID_TRANSITIONS,
    50→} from './MediaSessionState.js';
    51→import { MediaLifecycle } from './MediaLifecycle.js';
    52→import { MediaCoordinator } from './MediaCoordinator.js';
    53→import type {
    54→  MediaEvent,
    55→  MediaEventType,
    56→  MediaEventHandler,
    57→  MediaCreatedEvent,
    58→  MediaReadyEvent,
    59→  MediaStartedEvent,
    60→  MediaPausedEvent,
    61→  MediaInterruptedEvent,
    62→  MediaCompletedEvent,
    63→  MediaDestroyedEvent,
    64→  MediaErrorEvent,
    65→} from './MediaSessionEvents.js';
    66→import { VoiceEngineError, ErrorCode } from '../errors/index.js';
    67→import type { Timestamp, Nullable } from '../types/index.js';
    68→
    69→// ─── Public Interface ──────────────────────────────────────────────────────────
    70→
    71→/**
    72→ * Public contract for a single `MediaSession` instance.
    73→ */
    74→export interface IMediaSession {
    75→  /** The unique session identifier. */
    76→  readonly sessionId: string;
    77→
    78→  /** The current lifecycle state of the session. */
    79→  readonly state: MediaSessionState;
    80→
    81→  /**
    82→   * Wires all components and transitions CREATED → INITIALIZING → READY.
    83→   *
    84→   * @throws {VoiceEngineError} if called from an illegal state.
    85→   * @throws {VoiceEngineError} if any component fails to initialise.
    86→   */
    87→  initialize(): Promise<void>;
    88→
    89→  /**
    90→   * Begins the first conversational turn. Transitions READY → ACTIVE.
    91→   *
    92→   * @throws {VoiceEngineError} if called from an illegal state.
    93→   */
    94→  start(): Promise<void>;
    95→
    96→  /**
    97→   * Delivers a raw inbound audio chunk into the audio pipeline.
    98→   * Silently ignored if the session is not in an audio-accepting state.
    99→   *
   100→   * @param chunk - Inbound audio from the transport adapter.
   101→   * @param now   - Current monotonic timestamp in milliseconds.
   102→   */
   103→  deliverInboundAudio(chunk: AudioChunk, now: Timestamp): void;
   104→
   105→  /**
   106→   * Signals a barge-in detected by the transport adapter.
   107→   * Transitions ACTIVE → INTERRUPTED → ACTIVE if policy permits.
   108→   *
   109→   * @param now - Timestamp at which the interruption was detected.
   110→   */
   111→  signalInterruption(now: Timestamp): Promise<void>;
   112→
   113→  /**
   114→   * Temporarily suspends audio processing. Transitions ACTIVE → PAUSED.
   115→   *
   116→   * @param reason - Human-readable reason for the pause.
   117→   * @throws {VoiceEngineError} if called from an illegal state.
   118→   */
   119→  pause(reason: string): Promise<void>;
   120→
   121→  /**
   122→   * Resumes a paused session. Transitions PAUSED → ACTIVE.
   123→   *
   124→   * @throws {VoiceEngineError} if called from an illegal state.
   125→   */
   126→  resume(): Promise<void>;
   127→
   128→  /**
   129→   * Requests a graceful completion. Transitions ACTIVE | PAUSED →
   130→   * COMPLETING → COMPLETED.
   131→   *
   132→   * @param reason - Human-readable completion reason.
   133→   */
   134→  complete(reason: string): Promise<void>;
   135→
   136→  /**
   137→   * Releases all resources and transitions COMPLETED | FAILED → DESTROYED.
   138→   * Safe to call multiple times; subsequent calls are no-ops.
   139→   */
   140→  destroy(): void;
   141→
   142→  /** Subscribes to a typed session event. */
   143→  on<T extends MediaEventType>(
   144→    type: T,
   145→    handler: MediaEventHandler<Extract<MediaEvent, { type: T }>>
   146→  ): void;
   147→
   148→  /** Unsubscribes from a typed session event. */
   149→  off<T extends MediaEventType>(
   150→    type: T,
   151→    handler: MediaEventHandler<Extract<MediaEvent, { type: T }>>
   152→  ): void;
   153→}
   154→
   155→// ─── Implementation ────────────────────────────────────────────────────────────
   156→
   157→/**
   158→ * Production implementation of `IMediaSession`.
   159→ */
   160→export class MediaSession implements IMediaSession {
   161→  private readonly _ctx: Readonly<MediaSessionContext>;
   162→  private readonly _coordinator: MediaCoordinator;
   163→
   164→  private _state: MediaSessionState = MediaSessionState.CREATED;
   165→  private _createdAt: Timestamp;
   166→  private _readyAt: Nullable<Timestamp> = null;
   167→  private _destroyed = false;
   168→
   169→  private readonly _handlers = new Map<
   170→    MediaEventType,
   171→    Set<MediaEventHandler>
   172→  >();
   173→
   174→  constructor(ctx: Readonly<MediaSessionContext>) {
   175→    this._ctx = ctx;
   176→    this._createdAt = ctx.clock.now();
   177→
   178→    this._coordinator = new MediaCoordinator(
   179→      ctx,
   180→      this._handleTransition.bind(this),
   181→      this._handleError.bind(this)
   182→    );
   183→
   184→    this._emit({
   185→      type: 'media.created',
   186→      timestamp: this._createdAt,
   187→      sessionId: ctx.sessionId,
   188→      callSid: ctx.callSid,
   189→      campaignId: ctx.campaignId,
   190→    } satisfies MediaCreatedEvent);
   191→  }
   192→
   193→  // ─── Accessors ─────────────────────────────────────────────────────────────
   194→
   195→  get sessionId(): string {
   196→    return this._ctx.sessionId;
   197→  }
   198→
   199→  get state(): MediaSessionState {
   200→    return this._state;
   201→  }
   202→
   203→  // ─── Lifecycle ──────────────────────────────────────────────────────────────
   204→
   205→  async initialize(): Promise<void> {
   206→    this._assertNotDestroyed('initialize');
   207→    this._assertTransition(MediaSessionState.INITIALIZING, 'initialize');
   208→
   209→    this._ctx.logger.info('MediaSession initializing', {
   210→      sessionId: this._ctx.sessionId,
   211→      callSid: this._ctx.callSid,
   212→    });
   213→
   214→    this._setState(MediaSessionState.INITIALIZING);
   215→
   216→    try {
   217→      await this._ctx.runtime.initialize();
   218→      await this._ctx.runtime.connect();
   219→    } catch (err) {
   220→      this._transitionToFailed(err, MediaSessionState.INITIALIZING, false);
   221→      throw err;
   222→    }
   223→
   224→    const now = this._ctx.clock.now();
   225→    this._readyAt = now;
   226→    this._setState(MediaSessionState.READY);
   227→
   228→    this._emit({
   229→      type: 'media.ready',
   230→      timestamp: now,
   231→      sessionId: this._ctx.sessionId,
   232→      callSid: this._ctx.callSid,
   233→      initDurationMs: now - this._createdAt,
   234→    } satisfies MediaReadyEvent);
   235→
   236→    this._ctx.logger.info('MediaSession ready', {
   237→      initDurationMs: now - this._createdAt,
   238→    });
   239→  }
   240→
   241→  async start(): Promise<void> {
   242→    this._assertNotDestroyed('start');
   243→    this._assertTransition(MediaSessionState.ACTIVE, 'start');
   244→
   245→    this._ctx.logger.info('MediaSession starting');
   246→
   247→    try {
   248→      await this._coordinator.start();
   249→    } catch (err) {
   250→      this._transitionToFailed(err, MediaSessionState.READY, false);
   251→      throw err;
   252→    }
   253→
   254→    this._emit({
   255→      type: 'media.started',
   256→      timestamp: this._ctx.clock.now(),
   257→      sessionId: this._ctx.sessionId,
   258→      callSid: this._ctx.callSid,
   259→    } satisfies MediaStartedEvent);
   260→  }
   261→
   262→  deliverInboundAudio(chunk: AudioChunk, now: Timestamp): void {
   263→    if (this._destroyed) return;
   264→    this._coordinator.deliverInboundAudio(chunk, now);
   265→  }
   266→
   267→  async signalInterruption(now: Timestamp): Promise<void> {
   268→    if (this._destroyed) return;
   269→    await this._coordinator.signalInterruption(now);
   270→  }
   271→
   272→  async pause(reason: string): Promise<void> {
   273→    this._assertNotDestroyed('pause');
   274→    await this._coordinator.pause(reason);
   275→  }
   276→
   277→  async resume(): Promise<void> {
   278→    this._assertNotDestroyed('resume');
   279→    await this._coordinator.resume();
   280→  }
   281→
   282→  async complete(reason: string): Promise<void> {
   283→    this._assertNotDestroyed('complete');
   284→    await this._coordinator.requestCompletion(reason);
   285→  }
   286→
   287→  destroy(): void {
   288→    if (this._destroyed) return;
   289→    this._destroyed = true;
   290→
   291→    const fromState = this._state;
   292→    this._ctx.logger.info('MediaSession destroying', { fromState });
   293→
   294→    this._coordinator.destroy();
   295→    this._ctx.runtime.destroy();
   296→
   297→    this._state = MediaSessionState.DESTROYED;
   298→
   299→    this._emit({
   300→      type: 'media.destroyed',
   301→      timestamp: this._ctx.clock.now(),
   302→      sessionId: this._ctx.sessionId,
   303→      callSid: this._ctx.callSid,
   304→      destroyedFromState: fromState,
   305→    } satisfies MediaDestroyedEvent);
   306→
   307→    this._handlers.clear();
   308→  }
   309→
   310→  // ─── Event Bus ──────────────────────────────────────────────────────────────
   311→
   312→  on<T extends MediaEventType>(
   313→    type: T,
   314→    handler: MediaEventHandler<Extract<MediaEvent, { type: T }>>
   315→  ): void {
   316→    if (!this._handlers.has(type)) this._handlers.set(type, new Set());
   317→    this._handlers.get(type)!.add(handler as MediaEventHandler);
   318→  }
   319→
   320→  off<T extends MediaEventType>(
   321→    type: T,
   322→    handler: MediaEventHandler<Extract<MediaEvent, { type: T }>>
   323→  ): void {
   324→    this._handlers.get(type)?.delete(handler as MediaEventHandler);
   325→  }
   326→
   327→  // ─── Internal Transition Handlers ────────────────────────────────────────────
   328→
   329→  /**
   330→   * Called by `MediaCoordinator` whenever a state transition occurs.
   331→   */
   332→  private _handleTransition(
   333→    next: MediaSessionState,
   334→    meta?: Readonly<Record<string, unknown>>
   335→  ): void {
   336→    if (this._destroyed) return;
   337→
   338→    const prev = this._state;
   339→    this._state = next;
   340→
   341→    this._ctx.logger.debug('MediaSession state transition', {
   342→      from: prev,
   343→      to: next,
   344→    });
   345→
   346→    const now = this._ctx.clock.now();
   347→
   348→    switch (next) {
   349→      case MediaSessionState.PAUSED:
   350→        this._emit({
   351→          type: 'media.paused',
   352→          timestamp: now,
   353→          sessionId: this._ctx.sessionId,
   354→          callSid: this._ctx.callSid,
   355→          reason: String(meta?.['reason'] ?? 'requested'),
   356→        } satisfies MediaPausedEvent);
   357→        break;
   358→
   359→      case MediaSessionState.INTERRUPTED:
   360→        this._emit({
   361→          type: 'media.interrupted',
   362→          timestamp: now,
   363→          sessionId: this._ctx.sessionId,
   364→          callSid: this._ctx.callSid,
   365→          turnIndex: (meta?.['turnIndex'] as number) ?? 0,
   366→          agentAudioOffsetMs: (meta?.['agentAudioOffsetMs'] as number) ?? 0,
   367→        } satisfies MediaInterruptedEvent);
   368→        break;
   369→
   370→      case MediaSessionState.COMPLETED:
   371→        this._emit({
   372→          type: 'media.completed',
   373→          timestamp: now,
   374→          sessionId: this._ctx.sessionId,
   375→          callSid: this._ctx.callSid,
   376→          totalTurns: (meta?.['totalTurns'] as number) ?? 0,
   377→          durationMs: (meta?.['durationMs'] as number) ?? 0,
   378→          completionReason: String(meta?.['reason'] ?? 'completed'),
   379→        } satisfies MediaCompletedEvent);
   380→        break;
   381→
   382→      default:
   383→        break;
   384→    }
   385→  }
   386→
   387→  /**
   388→   * Called by `MediaCoordinator` when an unrecoverable error occurs.
   389→   */
   390→  private _handleError(
   391→    error: unknown,
   392→    fromState: MediaSessionState
   393→  ): void {
   394→    if (this._destroyed) return;
   395→    this._transitionToFailed(error, fromState, true);
   396→  }
   397→
   398→  // ─── Private Helpers ────────────────────────────────────────────────────────
   399→
   400→  private _setState(next: MediaSessionState): void {
   401→    this._state = next;
   402→  }
   403→
   404→  private _assertNotDestroyed(method: string): void {
   405→    if (this._destroyed) {
   406→      throw new VoiceEngineError(
   407→        `MediaSession.${method}() called after destroy()`,
   408→        ErrorCode.PIPELINE_ABORTED,
   409→        false,
   410→        { sessionId: this._ctx.sessionId }
   411→      );
   412→    }
   413→  }
   414→
   415→  private _assertTransition(next: MediaSessionState, method: string): void {
   416→    const result = MediaLifecycle.evaluate(this._state, next);
   417→    if (!result.allowed) {
   418→      throw new VoiceEngineError(
   419→        `MediaSession.${method}(): ${result.reason}`,
   420→        ErrorCode.PIPELINE_ABORTED,
   421→        false,
   422→        { sessionId: this._ctx.sessionId, currentState: this._state }
   423→      );
   424→    }
   425→  }
   426→
   427→  private _transitionToFailed(
   428→    error: unknown,
   429→    fromState: MediaSessionState,
   430→    providerError: boolean
   431→  ): void {
   432→    const legalPredecessors = MEDIA_VALID_TRANSITIONS[MediaSessionState.FAILED];
   433→    if (!legalPredecessors.has(fromState)) return;
   434→
   435→    this._state = MediaSessionState.FAILED;
   436→
   437→    const engineError =
   438→      error instanceof VoiceEngineError
   439→        ? error
   440→        : new VoiceEngineError(
   441→            String(error),
   442→            ErrorCode.PIPELINE_ABORTED,
   443→            false
   444→          );
   445→
   446→    this._ctx.logger.error('MediaSession failed', {
   447→      errorCode: engineError.code,
   448→      errorMessage: engineError.message,
   449→      failedInState: fromState,
   450→    });
   451→
   452→    this._emit({
   453→      type: 'media.error',
   454→      timestamp: this._ctx.clock.now(),
   455→      sessionId: this._ctx.sessionId,
   456→      callSid: this._ctx.callSid,
   457→      errorCode: engineError.code,
   458→      errorMessage: engineError.message,
   459→      failedInState: fromState,
   460→      providerError,
   461→    } satisfies MediaErrorEvent);
   462→  }
   463→
   464→  private _emit(event: MediaEvent): void {
   465→    const handlers = this._handlers.get(event.type);
   466→    if (!handlers) return;
   467→    Array.from(handlers).forEach((handler) => {
   468→      try {
   469→        handler(event);
   470→      } catch {
   471→        // Swallow — event delivery must never crash the session.
   472→      }
   473→    });
   474→  }
   475→}
