   353→        this._emit({ type: 'realtime.session_updated', timestamp: ts, eventId: event.event_id, session: event.session });
   354→        break;
   355→
   356→      case 'response.created':
   357→        this._emit({ type: 'realtime.response_started', timestamp: ts, eventId: event.event_id, responseId: event.response.id });
   358→        break;
   359→
   360→      case 'response.audio.delta':
   361→        this._emit({ type: 'realtime.audio_received', timestamp: ts, eventId: event.event_id, responseId: event.response_id, itemId: event.item_id, delta: event.delta });
   362→        break;
   363→
   364→      case 'response.audio_transcript.delta':
   365→        this._emit({ type: 'realtime.transcript_delta', timestamp: ts, eventId: event.event_id, responseId: event.response_id, itemId: event.item_id, delta: event.delta });
   366→        break;
   367→
   368→      case 'response.audio_transcript.done':
   369→        this._emit({ type: 'realtime.transcript_completed', timestamp: ts, eventId: event.event_id, responseId: event.response_id, itemId: event.item_id, transcript: event.transcript });
   370→        break;
   371→
   372→      case 'response.text.delta':
   373→        this._emit({ type: 'realtime.response_delta', timestamp: ts, eventId: event.event_id, responseId: event.response_id, itemId: event.item_id, delta: event.delta });
   374→        break;
   375→
   376→      case 'response.done':
   377→        this._emit({
   378→          type: 'realtime.response_completed',
   379→          timestamp: ts,
   380→          eventId: event.event_id,
   381→          responseId: event.response.id,
   382→          status: event.response.status as 'completed' | 'cancelled' | 'failed' | 'incomplete',
   383→          totalTokens: event.response.usage?.total_tokens ?? 0,
   384→          inputTokens: event.response.usage?.input_tokens ?? 0,
   385→          outputTokens: event.response.usage?.output_tokens ?? 0,
   386→        });
   387→        break;
   388→
   389→      case 'response.function_call_arguments.done':
   390→        this._emit({ type: 'realtime.tool_call', timestamp: ts, eventId: event.event_id, responseId: event.response_id, itemId: event.item_id, callId: event.call_id, functionName: event.name, arguments: event.arguments });
   391→        break;
   392→
   393→      case 'input_audio_buffer.speech_started':
   394→        this._emit({ type: 'realtime.speech_started', timestamp: ts, eventId: event.event_id, itemId: event.item_id, audioStartMs: event.audio_start_ms });
   395→        break;
   396→
   397→      case 'input_audio_buffer.speech_stopped':
   398→        this._emit({ type: 'realtime.speech_stopped', timestamp: ts, eventId: event.event_id, itemId: event.item_id, audioEndMs: event.audio_end_ms });
   399→        break;
   400→
   401→      case 'rate_limits.updated':
   402→        this._emit({ type: 'realtime.rate_limit', timestamp: ts, eventId: event.event_id, rateLimits: event.rate_limits });
   403→        break;
   404→
   405→      case 'error':
   406→        this._logger.error('OpenAI Realtime server error', { code: event.error.code, message: event.error.message });
   407→        this._emit({ type: 'realtime.error', timestamp: ts, eventId: event.event_id, errorType: event.error.type, errorCode: event.error.code, message: event.error.message, fatal: false });
   408→        break;
   409→
   410→      default:
   411→        break;
   412→    }
   413→  }
   414→
   415→  private _emit(event: RealtimeProviderEvent): void {
   416→    const handlers = this._handlers.get(event.type);
   417→    if (!handlers) return;
   418→    Array.from(handlers).forEach((handler) => {
   419→      try {
   420→        handler(event);
   421→      } catch (err) {
   422→        this._logger.warn('RealtimeSession event handler threw', { type: event.type, error: String(err) });
   423→      }
   424→    });
   425→  }
   426→
   427→  private _assertConnected(): void {
   428→    if (!this.isConnected) {
   429→      throw new ProviderError(
   430→        'OpenAIRealtimeSession is not connected',
   431→        ErrorCode.PROVIDER_UNAVAILABLE,
   432→        'openai-realtime'
   433→      );
   434→    }
   435→  }
   436→}
