/**
 * @module RealtimeBridge
 *
 * Connects a `MediaSession` to a `IOpenAIRealtimeSession`, owning the
 * bidirectional audio streaming channel, interrupt forwarding, and all
 * provider-side session events.
 *
 * ## Responsibilities
 * - Maintains the WebSocket session to the realtime AI provider.
 * - Forwards inbound audio (caller → provider) via `forwardAudio()`.
 * - Emits outbound audio events (provider → caller) via the `bridge.audio_ready`
 *   event for `OutboundAudioFlow` to consume.
 * - Detects server-side speech start (VAD barge-in) and calls
 *   `IMediaSession.signalInterruption()`.
 * - Exposes `interrupt()` to cancel the current provider response.
 *
 * ## Rules
 * - No OpenAI SDK imports.
 * - No Exotel protocol imports.
 * - Integration only through public interfaces.
 * - No business logic, no CRM, no MongoDB.
 *
 * ## Lifecycle
 * ```
 * new RealtimeBridge(deps)
 *   └─► connect()         — opens provider session, wires all event handlers
 *         ├─► forwardAudio(base64)   — sends caller audio to provider
 *         ├─► interrupt()            — cancels current provider response
 *         └─► disconnect()          — closes provider session, removes all listeners
 * ```
 */

import type { ILogger } from '../logger/index.js';
import type { IMediaSession } from '../media/MediaSession.js';
import type { IOpenAIRealtimeSession } from '../providers/openai/OpenAIRealtimeSession.js';
import type { Timestamp } from '../types/index.js';
import { VoiceEngineError, ErrorCode } from '../errors/index.js';

// ─── Bridge Event Types ───────────────────────────────────────────────────────

/** Payload emitted when the provider sends an outbound audio delta. */
export interface BridgeAudioReadyEvent {
  readonly type: 'bridge.audio_ready';
  /** Base64-encoded audio delta from the provider. */
  readonly base64Delta: string;
  /** Provider response identifier. */
  readonly responseId: string;
  /** Provider item identifier. */
  readonly itemId: string;
  /** Wall-clock timestamp. */
  readonly timestamp: Timestamp;
}

/** Payload emitted when the provider WebSocket disconnects. */
export interface BridgeDisconnectedEvent {
  readonly type: 'bridge.disconnected';
  /** WebSocket close code. */
  readonly code: number;
  /** Human-readable disconnect reason. */
  readonly reason: string;
  /** Whether the disconnect was clean (code === 1000). */
  readonly wasClean: boolean;
  readonly timestamp: Timestamp;
}

/** Payload emitted when the provider reports an error. */
export interface BridgeErrorEvent {
  readonly type: 'bridge.error';
  readonly message: string;
  readonly errorType: string;
  /** Whether this error is fatal to the session. */
  readonly fatal: boolean;
  readonly timestamp: Timestamp;
}

/** Payload emitted when the provider VAD detects speech start (barge-in signal). */
export interface BridgeSpeechDetectedEvent {
  readonly type: 'bridge.speech_detected';
  readonly audioStartMs: number;
  readonly timestamp: Timestamp;
}

/** Union of all events emitted by `RealtimeBridge`. */
export type BridgeEvent =
  | BridgeAudioReadyEvent
  | BridgeDisconnectedEvent
  | BridgeErrorEvent
  | BridgeSpeechDetectedEvent;

/** String union of all bridge event types. */
export type BridgeEventType = BridgeEvent['type'];

/** Handler signature for a typed bridge event. */
export type BridgeEventHandler<T extends BridgeEvent = BridgeEvent> = (event: T) => void;

// ─── Public Interface ─────────────────────────────────────────────────────────

/**
 * Public contract for the realtime bridge between `MediaSession`
 * and an AI provider realtime session.
 */
export interface IRealtimeBridge {
  /** Whether the provider session is currently connected. */
  readonly isConnected: boolean;

  /**
   * Opens the provider WebSocket session and wires all event handlers.
   * Must be called before `forwardAudio()` or `interrupt()`.
   *
   * @throws {VoiceEngineError} if the provider session fails to connect.
   */
  connect(): Promise<void>;

  /**
   * Forwards a base64-encoded audio payload to the AI provider.
   * Fire-and-forget; silently ignored if not connected.
   *
   * @param base64 - Base64-encoded audio chunk from the caller.
   */
  forwardAudio(base64: string): void;

  /**
   * Cancels the provider's current in-progress response (barge-in).
   * Silently ignored if not connected.
   */
  interrupt(): Promise<void>;

  /**
   * Gracefully closes the provider session and removes all event handlers.
   * Safe to call multiple times; subsequent calls are no-ops.
   */
  disconnect(): Promise<void>;

  /** Subscribes to a typed bridge event. */
  on<T extends BridgeEventType>(
    type: T,
    handler: BridgeEventHandler<Extract<BridgeEvent, { type: T }>>
  ): void;

  /** Unsubscribes from a typed bridge event. */
  off<T extends BridgeEventType>(
    type: T,
    handler: BridgeEventHandler<Extract<BridgeEvent, { type: T }>>
  ): void;
}

// ─── Dependencies ─────────────────────────────────────────────────────────────

/** Injected dependencies for `RealtimeBridge`. */
export interface RealtimeBridgeDependencies {
  /** The AI provider realtime session to bridge. */
  readonly providerSession: IOpenAIRealtimeSession;
  /** The media session that owns this call. */
  readonly mediaSession: IMediaSession;
  /** Structured logger. */
  readonly logger: ILogger;
  /** Session identifier for log correlation. */
  readonly sessionId: string;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Production implementation of `IRealtimeBridge`.
 */
export class RealtimeBridge implements IRealtimeBridge {
  private readonly _provider: IOpenAIRealtimeSession;
  private readonly _mediaSession: IMediaSession;
  private readonly _logger: ILogger;
  private readonly _sessionId: string;

  private _connected = false;
  private _destroyed = false;

  private readonly _handlers = new Map<BridgeEventType, Set<BridgeEventHandler>>();

  constructor(deps: Readonly<RealtimeBridgeDependencies>) {
    this._provider = deps.providerSession;
    this._mediaSession = deps.mediaSession;
    this._logger = deps.logger.child({ component: 'RealtimeBridge', sessionId: deps.sessionId });
    this._sessionId = deps.sessionId;
  }

  // ─── Accessors ───────────────────────────────────────────────────────────────

  get isConnected(): boolean {
    return this._connected && this._provider.isConnected;
  }

  // ─── Lifecycle ────────────────────────────────────────────────────────────────

  /**
   * Opens the provider WebSocket and registers all event handlers.
   */
  async connect(): Promise<void> {
    this._assertNotDestroyed('connect');

    this._logger.info('RealtimeBridge connecting to provider');

    this._wireProviderHandlers();

    try {
      await this._provider.connect();
    } catch (err) {
      this._logger.error('RealtimeBridge provider connect failed', { error: String(err) });
      throw new VoiceEngineError(
        `RealtimeBridge failed to connect provider: ${String(err)}`,
        ErrorCode.PROVIDER_UNAVAILABLE,
        true,
        { sessionId: this._sessionId }
      );
    }

    this._connected = true;
    this._logger.info('RealtimeBridge connected');
  }

  /**
   * Forwards caller audio to the AI provider.
   * Fire-and-forget; silently ignored when not connected.
   */
  forwardAudio(base64: string): void {
    if (!this.isConnected || this._destroyed) return;
    this._provider.sendAudio(base64);
  }

  /**
   * Cancels the current provider response (barge-in).
   */
  async interrupt(): Promise<void> {
    if (!this.isConnected || this._destroyed) return;

    this._logger.debug('RealtimeBridge signalling interrupt to provider');
    await this._provider.interrupt();
  }

  /**
   * Closes the provider session and removes all handlers.
   */
  async disconnect(): Promise<void> {
    if (this._destroyed) return;
    this._destroyed = true;
    this._connected = false;

    this._logger.info('RealtimeBridge disconnecting');
    await this._provider.close();
    this._handlers.clear();
  }

  // ─── Event Bus ───────────────────────────────────────────────────────────────

  on<T extends BridgeEventType>(
    type: T,
    handler: BridgeEventHandler<Extract<BridgeEvent, { type: T }>>
  ): void {
    if (!this._handlers.has(type)) this._handlers.set(type, new Set());
    this._handlers.get(type)!.add(handler as BridgeEventHandler);
  }

  off<T extends BridgeEventType>(
    type: T,
    handler: BridgeEventHandler<Extract<BridgeEvent, { type: T }>>
  ): void {
    this._handlers.get(type)?.delete(handler as BridgeEventHandler);
  }

  // ─── Private: Provider Event Wiring ─────────────────────────────────────────

  /**
   * Registers all necessary event handlers on the provider session.
   * Called once during `connect()`.
   */
  private _wireProviderHandlers(): void {
    // Outbound audio from AI → caller
    this._provider.on('realtime.audio_received', (event) => {
      if (this._destroyed) return;
      this._emit({
        type: 'bridge.audio_ready',
        base64Delta: event.delta,
        responseId: event.responseId,
        itemId: event.itemId,
        timestamp: event.timestamp,
      } satisfies BridgeAudioReadyEvent);
    });

    // Server VAD detected caller speech → barge-in signal
    this._provider.on('realtime.speech_started', (event) => {
      if (this._destroyed) return;
      const now = Date.now() as Timestamp;

      this._logger.debug('RealtimeBridge: provider VAD speech_started, signalling interruption', {
        audioStartMs: event.audioStartMs,
      });

      this._emit({
        type: 'bridge.speech_detected',
        audioStartMs: event.audioStartMs,
        timestamp: now,
      } satisfies BridgeSpeechDetectedEvent);

      // Signal barge-in to the media session
      this._mediaSession.signalInterruption(now).catch((err: unknown) => {
        this._logger.warn('RealtimeBridge: mediaSession.signalInterruption failed', {
          error: String(err),
        });
      });
    });

    // Provider WebSocket disconnected
    this._provider.on('realtime.disconnected', (event) => {
      if (this._destroyed) return;
      this._connected = false;

      this._logger.info('RealtimeBridge: provider disconnected', {
        code: event.code,
        reason: event.reason,
      });

      this._emit({
        type: 'bridge.disconnected',
        code: event.code,
        reason: event.reason,
        wasClean: event.wasClean,
        timestamp: event.timestamp,
      } satisfies BridgeDisconnectedEvent);
    });

    // Provider error
    this._provider.on('realtime.error', (event) => {
      if (this._destroyed) return;

      this._logger.error('RealtimeBridge: provider error', {
        errorType: event.errorType,
        message: event.message,
        fatal: event.fatal,
      });

      this._emit({
        type: 'bridge.error',
        message: event.message,
        errorType: event.errorType,
        fatal: event.fatal,
        timestamp: event.timestamp,
      } satisfies BridgeErrorEvent);
    });
  }

  // ─── Private Helpers ─────────────────────────────────────────────────────────

  private _assertNotDestroyed(method: string): void {
    if (this._destroyed) {
      throw new VoiceEngineError(
        `RealtimeBridge.${method}() called after disconnect()`,
        ErrorCode.PIPELINE_ABORTED,
        false,
        { sessionId: this._sessionId }
      );
    }
  }

  private _emit(event: BridgeEvent): void {
    const handlers = this._handlers.get(event.type);
    if (!handlers) return;
    Array.from(handlers).forEach((handler) => {
      try {
        handler(event);
      } catch (err) {
        this._logger.warn('RealtimeBridge: event handler threw', {
          type: event.type,
          error: String(err),
        });
      }
    });
  }
}

/**
 * @module InboundAudioFlow
 *
 * Drives the inbound audio pipeline:
 * ```
 * Transport → MediaSession → AudioEngine → RealtimeBridge
 * ```
 *
 * ## Responsibilities
 * - Subscribes to `transport.audio_received` events from `ITransportGateway`.
 * - Guards on `IMediaSession.state` — only forwards audio when the session
 *   is in an audio-accepting state (ACTIVE).
 * - Ingests each inbound chunk into `IAudioEngine.ingestInbound()`.
 * - Ticks the inbound pipeline via `IAudioEngine.tickInbound()` to produce
 *   the scheduled chunks.
 * - Forwards scheduled chunks to `IRealtimeBridge.forwardAudio()` for
 *   transmission to the AI provider.
 *
 * ## Rules
 * - No transport protocol (no Exotel, no WebSocket protocol specifics).
 * - No OpenAI SDK imports.
 * - No business logic, no CRM, no MongoDB.
 * - Dependency Injection only.
 *
 * ## Performance
 * All processing is synchronous within each event callback to avoid
 * additional scheduling overhead. Target: <10 ms per chunk in the hot path.
 */

import type { ILogger } from '../logger/index.js';
import type { IMediaSession } from '../media/MediaSession.js';
import type { IAudioEngine } from '../audio-engine/AudioEngine.js';
import type { ITransportGateway } from '../transport/TransportGateway.js';
import type { TransportAudioReceivedEvent } from '../transport/TransportEvents.js';
import type { IRealtimeBridge } from './RealtimeBridge.js';
import { MediaSessionState } from '../media/MediaSessionState.js';
import { createAudioChunk } from '../audio-engine/AudioChunk.js';

// ─── Configuration ────────────────────────────────────────────────────────────

/**
 * Tuning configuration for `InboundAudioFlow`.
 */
export interface InboundAudioFlowConfig {
  /**
   * Whether to tick the inbound pipeline after each ingest.
   * Defaults to `true`. Set `false` to drive ticks externally.
   */
  readonly tickOnIngest: boolean;
}

const DEFAULT_INBOUND_CONFIG: Readonly<InboundAudioFlowConfig> = Object.freeze({
  tickOnIngest: true,
});

// ─── Dependencies ─────────────────────────────────────────────────────────────

/** Injected dependencies for `InboundAudioFlow`. */
export interface InboundAudioFlowDependencies {
  /** Transport gateway to subscribe to inbound audio events. */
  readonly transport: ITransportGateway;
  /** Media session used to gate audio forwarding by lifecycle state. */
  readonly mediaSession: IMediaSession;
  /** Audio engine for inbound pipeline processing. */
  readonly audioEngine: IAudioEngine;
  /** Realtime bridge to forward processed chunks to the AI provider. */
  readonly bridge: IRealtimeBridge;
  /** Structured logger. */
  readonly logger: ILogger;
  /** Session identifier for log correlation. */
  readonly sessionId: string;
  /** Optional config overrides. */
  readonly config?: Partial<InboundAudioFlowConfig>;
}

// ─── Public Interface ─────────────────────────────────────────────────────────

/**
 * Public contract for the inbound audio flow pipeline.
 */
export interface IInboundAudioFlow {
  /**
   * Attaches all transport event listeners and begins forwarding
   * inbound audio to the AI provider.
   *
   * Must be called after the transport session is established and
   * the realtime bridge is connected.
   */
  start(): void;

  /**
   * Detaches all transport event listeners and stops forwarding audio.
   * Safe to call multiple times; subsequent calls are no-ops.
   */
  stop(): void;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Production implementation of `IInboundAudioFlow`.
 */
export class InboundAudioFlow implements IInboundAudioFlow {
  private readonly _transport: ITransportGateway;
  private readonly _mediaSession: IMediaSession;
  private readonly _audioEngine: IAudioEngine;
  private readonly _bridge: IRealtimeBridge;
  private readonly _logger: ILogger;
  private readonly _sessionId: string;
  private readonly _config: Readonly<InboundAudioFlowConfig>;

  private _active = false;
  private _chunkSequence = 0;

  /**
   * Bound handler reference retained so it can be passed to `off()` exactly.
   */
  private readonly _onAudioReceived: (event: TransportAudioReceivedEvent) => void;

  constructor(deps: Readonly<InboundAudioFlowDependencies>) {
    this._transport = deps.transport;
    this._mediaSession = deps.mediaSession;
    this._audioEngine = deps.audioEngine;
    this._bridge = deps.bridge;
    this._logger = deps.logger.child({ component: 'InboundAudioFlow', sessionId: deps.sessionId });
    this._sessionId = deps.sessionId;
    this._config = Object.freeze({ ...DEFAULT_INBOUND_CONFIG, ...deps.config });

    // Pre-bind to allow clean `off()` reference equality.
    this._onAudioReceived = this._handleAudioReceived.bind(this);
  }

  // ─── Lifecycle ────────────────────────────────────────────────────────────────

  /**
   * Attaches the inbound audio listener to the transport gateway.
   */
  start(): void {
    if (this._active) return;
    this._active = true;
    this._transport.on('transport.audio_received', this._onAudioReceived);
    this._logger.info('InboundAudioFlow started');
  }

  /**
   * Detaches the inbound audio listener from the transport gateway.
   */
  stop(): void {
    if (!this._active) return;
    this._active = false;
    this._transport.off('transport.audio_received', this._onAudioReceived);
    this._logger.info('InboundAudioFlow stopped');
  }

  // ─── Private: Hot Path ───────────────────────────────────────────────────────

  /**
   * Called for every inbound audio frame received by the transport gateway.
   *
   * Guards:
   * 1. MediaSession must be in the ACTIVE state.
   * 2. AudioEngine must be running.
   * 3. Bridge must be connected.
   *
   * @param event - Decoded transport audio event.
   */
  private _handleAudioReceived(event: TransportAudioReceivedEvent): void {
    // Guard 1 — session state
    if (this._mediaSession.state !== MediaSessionState.ACTIVE) return;

    // Guard 2 — audio engine
    if (!this._audioEngine.isRunning) return;

    // Guard 3 — bridge
    if (!this._bridge.isConnected) return;

    // Build an immutable AudioChunk from the transport event
    const chunk = createAudioChunk({
      sequence: this._chunkSequence++,
      timestamp: event.timestamp,
      sampleRate: event.sampleRate,
      encoding: this._resolveEncoding(event.encoding),
      durationMs: this._estimateDurationMs(event.base64Payload, event.sampleRate),
      payload: event.base64Payload,
      payloadFormat: 'base64',
      direction: 'inbound',
      trackId: event.trackId,
    });

    // Ingest into the audio engine inbound pipeline
    try {
      this._audioEngine.ingestInbound(chunk);
    } catch (err) {
      this._logger.warn('InboundAudioFlow: audioEngine.ingestInbound failed', {
        error: String(err),
        sequence: chunk.sequence,
      });
      return;
    }

    // Tick the pipeline to obtain scheduled chunks
    if (!this._config.tickOnIngest) return;

    const result = this._audioEngine.tickInbound(null);

    // Forward each scheduled chunk to the AI provider
    for (const scheduled of result.chunksToSend) {
      const base64 = this._toBase64(scheduled.payload);
      if (base64.length > 0) {
        this._bridge.forwardAudio(base64);
      }
    }
  }

  // ─── Private Helpers ─────────────────────────────────────────────────────────

  /**
   * Converts a payload to a base64 string.
   * When the payload is already a base64 string, returns it directly.
   * When the payload is a `Uint8Array`, converts via Buffer.
   */
  private _toBase64(payload: Uint8Array | string): string {
    if (typeof payload === 'string') return payload;
    return Buffer.from(payload).toString('base64');
  }

  /**
   * Resolves the raw encoding string from the transport event to a typed
   * `AudioEncoding`. Falls back to `'mulaw'` for unrecognised encodings.
   */
  private _resolveEncoding(raw: string): 'pcm' | 'pcm16' | 'linear16' | 'mulaw' | 'alaw' | 'opus' {
    const known = new Set(['pcm', 'pcm16', 'linear16', 'mulaw', 'alaw', 'opus']);
    return known.has(raw)
      ? (raw as 'pcm' | 'pcm16' | 'linear16' | 'mulaw' | 'alaw' | 'opus')
      : 'mulaw';
  }

  /**
   * Estimates the audio duration of a base64-encoded μ-law payload.
   * μ-law: 1 byte per sample at the declared sample rate.
   */
  private _estimateDurationMs(base64Payload: string, sampleRate: number): number {
    if (sampleRate <= 0 || base64Payload.length === 0) return 0;
    const byteLength = Math.floor(base64Payload.length * 0.75);
    return Math.round((byteLength / sampleRate) * 1000);
  }
}

/**
 * @module OutboundAudioFlow
 *
 * Drives the outbound audio pipeline:
 * ```
 * RealtimeBridge → AudioEngine → MediaSession → Transport
 * ```
 *
 * ## Responsibilities
 * - Subscribes to `bridge.audio_ready` events from `IRealtimeBridge`.
 * - Ingests each provider audio delta into `IAudioEngine.ingestOutbound()`.
 * - Ticks the outbound pipeline via `IAudioEngine.tickOutbound()` to produce
 *   scheduled chunks.
 * - Delivers each scheduled chunk to the caller via
 *   `ITransportGateway.sendAudio()`.
 * - On `bridge.speech_detected` (barge-in): flushes the outbound pipeline and
 *   sends a clear command to the transport to silence buffered audio at the
 *   provider end.
 *
 * ## Rules
 * - No OpenAI SDK imports.
 * - No Exotel protocol imports.
 * - No business logic, no CRM, no MongoDB.
 * - Dependency Injection only.
 *
 * ## Performance
 * All processing is synchronous within each event callback.
 * Target: <10 ms per chunk in the hot path.
 */

import type { ILogger } from '../logger/index.js';
import type { IAudioEngine } from '../audio-engine/AudioEngine.js';
import type { ITransportGateway } from '../transport/TransportGateway.js';
import type { AudioChunk } from '../audio-engine/AudioChunk.js';
import type { SessionId } from '../types/index.js';
import type {
  IRealtimeBridge,
  BridgeAudioReadyEvent,
  BridgeSpeechDetectedEvent,
} from './RealtimeBridge.js';
import { createAudioChunk } from '../audio-engine/AudioChunk.js';

// ─── Configuration ────────────────────────────────────────────────────────────

/**
 * Audio format configuration for chunks arriving from the AI provider.
 * These values must match the session configuration negotiated with the provider.
 */
export interface OutboundAudioFormat {
  /** Sample rate of the provider's output audio in Hz (e.g. 8000, 24000). */
  readonly sampleRate: number;
  /** Encoding of the provider's output audio. */
  readonly encoding: 'pcm' | 'pcm16' | 'linear16' | 'mulaw' | 'alaw' | 'opus';
}

/**
 * Tuning configuration for `OutboundAudioFlow`.
 */
export interface OutboundAudioFlowConfig {
  /** Audio format of the provider's output stream. Defaults to PCM16 at 24 kHz. */
  readonly audioFormat: OutboundAudioFormat;
  /**
   * Whether to tick the outbound pipeline after each ingest.
   * Defaults to `true`. Set `false` to drive ticks externally.
   */
  readonly tickOnIngest: boolean;
}

const DEFAULT_OUTBOUND_CONFIG: Readonly<OutboundAudioFlowConfig> = Object.freeze({
  audioFormat: Object.freeze({ sampleRate: 8000, encoding: 'mulaw' as const }),
  tickOnIngest: true,
});

// ─── Dependencies ─────────────────────────────────────────────────────────────

/** Injected dependencies for `OutboundAudioFlow`. */
export interface OutboundAudioFlowDependencies {
  /** Realtime bridge to receive outbound audio from the AI provider. */
  readonly bridge: IRealtimeBridge;
  /** Audio engine for outbound pipeline processing. */
  readonly audioEngine: IAudioEngine;
  /** Transport gateway to deliver processed audio to the caller. */
  readonly transport: ITransportGateway;
  /** Session identifier used to address the correct transport connection. */
  readonly sessionId: SessionId;
  /** Structured logger. */
  readonly logger: ILogger;
  /** Optional config overrides. */
  readonly config?: Partial<OutboundAudioFlowConfig>;
}

// ─── Public Interface ─────────────────────────────────────────────────────────

/**
 * Public contract for the outbound audio flow pipeline.
 */
export interface IOutboundAudioFlow {
  /**
   * Attaches all bridge event listeners and begins forwarding
   * AI provider audio to the caller.
   *
   * Must be called after the realtime bridge is connected and the
   * transport session is established.
   */
  start(): void;

  /**
   * Detaches all bridge event listeners and stops forwarding audio.
   * Safe to call multiple times; subsequent calls are no-ops.
   */
  stop(): void;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Production implementation of `IOutboundAudioFlow`.
 */
export class OutboundAudioFlow implements IOutboundAudioFlow {
  private readonly _bridge: IRealtimeBridge;
  private readonly _audioEngine: IAudioEngine;
  private readonly _transport: ITransportGateway;
  private readonly _sessionId: SessionId;
  private readonly _logger: ILogger;
  private readonly _config: Readonly<OutboundAudioFlowConfig>;

  private _active = false;
  private _chunkSequence = 0;

  /**
   * Pre-bound handler references retained for clean `off()` equality.
   */
  private readonly _onAudioReady: (event: BridgeAudioReadyEvent) => void;
  private readonly _onSpeechDetected: (event: BridgeSpeechDetectedEvent) => void;

  constructor(deps: Readonly<OutboundAudioFlowDependencies>) {
    this._bridge = deps.bridge;
    this._audioEngine = deps.audioEngine;
    this._transport = deps.transport;
    this._sessionId = deps.sessionId;
    this._logger = deps.logger.child({ component: 'OutboundAudioFlow', sessionId: deps.sessionId });
    this._config = Object.freeze({
      ...DEFAULT_OUTBOUND_CONFIG,
      ...deps.config,
      audioFormat: Object.freeze({
        ...DEFAULT_OUTBOUND_CONFIG.audioFormat,
        ...deps.config?.audioFormat,
      }),
    });

    this._onAudioReady = this._handleAudioReady.bind(this);
    this._onSpeechDetected = this._handleSpeechDetected.bind(this);
  }

  // ─── Lifecycle ────────────────────────────────────────────────────────────────

  /**
   * Attaches bridge event listeners and begins outbound audio forwarding.
   */
  start(): void {
    if (this._active) return;
    this._active = true;
    this._bridge.on('bridge.audio_ready', this._onAudioReady);
    this._bridge.on('bridge.speech_detected', this._onSpeechDetected);
    this._logger.info('OutboundAudioFlow started');
  }

  /**
   * Detaches bridge event listeners and stops outbound audio forwarding.
   */
  stop(): void {
    if (!this._active) return;
    this._active = false;
    this._bridge.off('bridge.audio_ready', this._onAudioReady);
    this._bridge.off('bridge.speech_detected', this._onSpeechDetected);
    this._logger.info('OutboundAudioFlow stopped');
  }

  // ─── Private: Hot Paths ───────────────────────────────────────────────────────

  /**
   * Called for every audio delta received from the AI provider.
   * Ingests into the outbound pipeline and delivers scheduled chunks to transport.
   *
   * @param event - Provider audio ready event from the bridge.
   */
  private _handleAudioReady(event: BridgeAudioReadyEvent): void {
    if (!this._audioEngine.isRunning) return;

    const chunk = this._buildChunk(event.base64Delta, event.timestamp);

    try {
      this._audioEngine.ingestOutbound(chunk);
    } catch (err) {
      this._logger.warn('OutboundAudioFlow: audioEngine.ingestOutbound failed', {
        error: String(err),
        sequence: chunk.sequence,
      });
      return;
    }

    if (!this._config.tickOnIngest) return;

    const result = this._audioEngine.tickOutbound(null);

    for (const scheduled of result.chunksToSend) {
      this._transport.sendAudio(this._sessionId, scheduled as AudioChunk);
    }
  }

  /**
   * Called when the provider VAD signals that the caller began speaking
   * (barge-in). Flushes the outbound pipeline and clears the transport buffer
   * to stop audio playback immediately.
   */
  private _handleSpeechDetected(_event: BridgeSpeechDetectedEvent): void {
    if (!this._audioEngine.isRunning) return;

    this._logger.debug('OutboundAudioFlow: barge-in detected, flushing outbound pipeline');

    // Flush the engine pipeline (drain any buffered frames)
    const flushResult = this._audioEngine.flushOutbound();

    // Deliver any remaining frames before clearing
    for (const scheduled of flushResult.chunksToSend) {
      this._transport.sendAudio(this._sessionId, scheduled as AudioChunk);
    }

    // Clear transport buffer — stops audio playback at the telephony provider
    this._transport.sendClear(this._sessionId);

    this._logger.debug('OutboundAudioFlow: outbound flushed and transport cleared', {
      flushedChunks: flushResult.chunksToSend.length,
    });
  }

  // ─── Private Helpers ─────────────────────────────────────────────────────────

  /**
   * Builds an immutable outbound `AudioChunk` from a provider audio delta.
   *
   * @param base64Delta - Base64-encoded audio from the provider.
   * @param timestamp   - Wall-clock timestamp of the event.
   */
  private _buildChunk(base64Delta: string, timestamp: number): Readonly<AudioChunk> {
    const { sampleRate, encoding } = this._config.audioFormat;
    const byteLength = Math.floor(base64Delta.length * 0.75);
    const durationMs = sampleRate > 0
      ? Math.round((byteLength / sampleRate) * 1000)
      : 0;

    return createAudioChunk({
      sequence: this._chunkSequence++,
      timestamp,
      sampleRate,
      encoding,
      durationMs,
      payload: base64Delta,
      payloadFormat: 'base64',
      direction: 'outbound',
    });
  }
}

/**
 * @module SessionSupervisor
 *
 * Monitors a live call session for timeouts, disconnections, provider
 * failures, and heartbeat health — and triggers graceful recovery when
 * thresholds are breached.
 *
 * ## Responsibilities
 * - Periodic heartbeat timer that detects stale sessions (no activity).
 * - Inactivity timeout: calls `IMediaSession.complete('session_timeout')`
 *   when no audio is received within the configured window.
 * - Provider failure monitoring: calls `IMediaSession.complete('provider_failure')`
 *   on fatal bridge errors.
 * - Disconnect monitoring: calls `IMediaSession.complete('transport_disconnected')`
 *   when the bridge reports a provider disconnect.
 * - Records last-activity timestamp on each heartbeat tick.
 *
 * ## Rules
 * - No business logic.
 * - No CRM, no MongoDB, no campaign queries.
 * - No OpenAI SDK imports.
 * - No Exotel protocol imports.
 * - Dependency Injection only.
 *
 * ## Recovery Philosophy
 * `SessionSupervisor` never retries connections itself. It delegates all
 * recovery decisions to the `IMediaSession` via its public interface.
 * The supervisor only detects anomalies and calls the correct lifecycle method.
 */

import type { ILogger } from '../logger/index.js';
import type { IMediaSession } from '../media/MediaSession.js';
import type {
  IRealtimeBridge,
  BridgeDisconnectedEvent,
  BridgeErrorEvent,
} from './RealtimeBridge.js';
import { MediaSessionState, MEDIA_TERMINAL_STATES } from '../media/MediaSessionState.js';

// ─── Configuration ────────────────────────────────────────────────────────────

/**
 * Timing configuration for `SessionSupervisor`.
 */
export interface SessionSupervisorConfig {
  /**
   * Interval in milliseconds between heartbeat ticks.
   * Defaults to 5 000 ms.
   */
  readonly heartbeatIntervalMs: number;

  /**
   * Maximum milliseconds of inactivity before the session is timed out.
   * "Activity" is defined as any inbound audio chunk being delivered.
   * Defaults to 30 000 ms.
   */
  readonly inactivityTimeoutMs: number;

  /**
   * Whether to complete the session on a non-fatal provider error.
   * When `false`, only fatal provider errors trigger session completion.
   * Defaults to `false`.
   */
  readonly completeOnNonFatalError: boolean;
}

const DEFAULT_SUPERVISOR_CONFIG: Readonly<SessionSupervisorConfig> = Object.freeze({
  heartbeatIntervalMs: 5_000,
  inactivityTimeoutMs: 30_000,
  completeOnNonFatalError: false,
});

// ─── Dependencies ─────────────────────────────────────────────────────────────

/** Injected dependencies for `SessionSupervisor`. */
export interface SessionSupervisorDependencies {
  /** Media session to monitor and signal lifecycle events on. */
  readonly mediaSession: IMediaSession;
  /** Realtime bridge to monitor for provider disconnects and errors. */
  readonly bridge: IRealtimeBridge;
  /** Structured logger. */
  readonly logger: ILogger;
  /** Session identifier for log correlation. */
  readonly sessionId: string;
  /** Optional configuration overrides. */
  readonly config?: Partial<SessionSupervisorConfig>;
}

// ─── Public Interface ─────────────────────────────────────────────────────────

/**
 * Public contract for `SessionSupervisor`.
 */
export interface ISessionSupervisor {
  /**
   * Begins heartbeat monitoring and bridge event observation.
   * Must be called after the bridge is connected and the media session is ACTIVE.
   */
  start(): void;

  /**
   * Stops all monitoring timers and removes bridge event listeners.
   * Safe to call multiple times; subsequent calls are no-ops.
   */
  stop(): void;

  /**
   * Records a new activity timestamp. Call this whenever meaningful
   * session activity is detected (e.g. inbound audio received).
   */
  recordActivity(): void;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Production implementation of `ISessionSupervisor`.
 */
export class SessionSupervisor implements ISessionSupervisor {
  private readonly _mediaSession: IMediaSession;
  private readonly _bridge: IRealtimeBridge;
  private readonly _logger: ILogger;
  private readonly _sessionId: string;
  private readonly _config: Readonly<SessionSupervisorConfig>;

  private _active = false;
  private _lastActivityAt: number = Date.now();
  private _heartbeatTimer: ReturnType<typeof setInterval> | null = null;

  /**
   * Pre-bound handler references retained for clean `off()` equality.
   */
  private readonly _onBridgeDisconnected: (event: BridgeDisconnectedEvent) => void;
  private readonly _onBridgeError: (event: BridgeErrorEvent) => void;

  constructor(deps: Readonly<SessionSupervisorDependencies>) {
    this._mediaSession = deps.mediaSession;
    this._bridge = deps.bridge;
    this._logger = deps.logger.child({
      component: 'SessionSupervisor',
      sessionId: deps.sessionId,
    });
    this._sessionId = deps.sessionId;
    this._config = Object.freeze({ ...DEFAULT_SUPERVISOR_CONFIG, ...deps.config });

    this._onBridgeDisconnected = this._handleBridgeDisconnected.bind(this);
    this._onBridgeError = this._handleBridgeError.bind(this);
  }

  // ─── Lifecycle ────────────────────────────────────────────────────────────────

  /**
   * Starts the heartbeat timer and subscribes to bridge failure events.
   */
  start(): void {
    if (this._active) return;
    this._active = true;
    this._lastActivityAt = Date.now();

    this._bridge.on('bridge.disconnected', this._onBridgeDisconnected);
    this._bridge.on('bridge.error', this._onBridgeError);

    this._heartbeatTimer = setInterval(
      () => this._tick(),
      this._config.heartbeatIntervalMs
    );

    this._logger.info('SessionSupervisor started', {
      heartbeatIntervalMs: this._config.heartbeatIntervalMs,
      inactivityTimeoutMs: this._config.inactivityTimeoutMs,
    });
  }

  /**
   * Stops the heartbeat timer and removes bridge event listeners.
   */
  stop(): void {
    if (!this._active) return;
    this._active = false;

    if (this._heartbeatTimer !== null) {
      clearInterval(this._heartbeatTimer);
      this._heartbeatTimer = null;
    }

    this._bridge.off('bridge.disconnected', this._onBridgeDisconnected);
    this._bridge.off('bridge.error', this._onBridgeError);

    this._logger.info('SessionSupervisor stopped');
  }

  /**
   * Updates the last-activity timestamp.
   * Call this whenever inbound audio is delivered.
   */
  recordActivity(): void {
    this._lastActivityAt = Date.now();
  }

  // ─── Private: Heartbeat ───────────────────────────────────────────────────────

  /**
   * Runs on each heartbeat interval.
   * Checks for inactivity timeout and session terminal state.
   */
  private _tick(): void {
    if (!this._active) return;

    const sessionState = this._mediaSession.state;

    // Stop supervising if the session has already terminated.
    if (MEDIA_TERMINAL_STATES.has(sessionState)) {
      this._logger.info('SessionSupervisor: session reached terminal state, stopping', {
        state: sessionState,
      });
      this.stop();
      return;
    }

    // Only enforce inactivity timeout when the session is ACTIVE.
    if (sessionState !== MediaSessionState.ACTIVE) return;

    const idleMs = Date.now() - this._lastActivityAt;

    this._logger.debug('SessionSupervisor heartbeat', {
      sessionState,
      idleMs,
      inactivityTimeoutMs: this._config.inactivityTimeoutMs,
    });

    if (idleMs >= this._config.inactivityTimeoutMs) {
      this._logger.warn('SessionSupervisor: inactivity timeout exceeded, completing session', {
        idleMs,
        threshold: this._config.inactivityTimeoutMs,
      });
      this._completeSession('session_timeout');
    }
  }

  // ─── Private: Bridge Event Handlers ──────────────────────────────────────────

  /**
   * Called when the realtime bridge reports a provider disconnect.
   * Signals graceful session completion via `IMediaSession.complete()`.
   */
  private _handleBridgeDisconnected(event: BridgeDisconnectedEvent): void {
    this._logger.warn('SessionSupervisor: bridge disconnected, completing session', {
      code: event.code,
      reason: event.reason,
      wasClean: event.wasClean,
    });
    this._completeSession('provider_disconnected');
  }

  /**
   * Called when the realtime bridge reports a provider error.
   * Completes the session on fatal errors (or all errors if configured).
   */
  private _handleBridgeError(event: BridgeErrorEvent): void {
    if (!event.fatal && !this._config.completeOnNonFatalError) {
      this._logger.warn('SessionSupervisor: non-fatal provider error (ignoring)', {
        errorType: event.errorType,
        message: event.message,
      });
      return;
    }

    this._logger.error('SessionSupervisor: provider error, completing session', {
      errorType: event.errorType,
      message: event.message,
      fatal: event.fatal,
    });
    this._completeSession('provider_failure');
  }

  // ─── Private Helpers ─────────────────────────────────────────────────────────

  /**
   * Attempts a graceful session completion with a given reason.
   * Stops the supervisor after initiating completion.
   *
   * @param reason - Human-readable completion reason.
   */
  private _completeSession(reason: string): void {
    this.stop();

    if (MEDIA_TERMINAL_STATES.has(this._mediaSession.state)) return;

    this._mediaSession.complete(reason).catch((err: unknown) => {
      this._logger.error('SessionSupervisor: mediaSession.complete() failed', {
        reason,
        error: String(err),
        sessionId: this._sessionId,
      });
    });
  }
}

/**
 * @module RuntimeIntegration
 *
 * The final executable integration that wires together all Voice Engine V2
 * components into a single, runnable phone conversation.
 *
 * ## Ownership
 * `RuntimeIntegration` is the single object that owns the full lifecycle of:
 * - `IRealtimeBridge`     — provider ↔ media session audio channel
 * - `IInboundAudioFlow`   — Transport → AudioEngine → Bridge pipeline
 * - `IOutboundAudioFlow`  — Bridge → AudioEngine → Transport pipeline
 * - `ISessionSupervisor`  — Timeout / disconnect / heartbeat monitoring
 *
 * ## Lifecycle
 * ```
 * new RuntimeIntegration(deps)
 *   └─► start()     — initialize bridge, start flows & supervisor, start media session
 *         └─► stop()     — graceful stop (complete session, stop flows & supervisor)
 *               └─► shutdown() — forced teardown (stop all, destroy media session)
 * ```
 *
 * ## Rules
 * - No OpenAI SDK imports.
 * - No Exotel protocol imports.
 * - No business logic, no CRM, no MongoDB.
 * - Dependency Injection only through `RuntimeIntegrationDependencies`.
 * - Integration only through public interfaces.
 */

import type { ILogger } from '../logger/index.js';
import type { IMediaSession } from '../media/MediaSession.js';
import type { IAudioEngine } from '../audio-engine/AudioEngine.js';
import type { ITransportGateway } from '../transport/TransportGateway.js';
import type { SessionId } from '../types/index.js';
import type { IRealtimeBridge } from './RealtimeBridge.js';
import type { IInboundAudioFlow } from './InboundAudioFlow.js';
import type { IOutboundAudioFlow } from './OutboundAudioFlow.js';
import type { ISessionSupervisor } from './SessionSupervisor.js';
import { VoiceEngineError, ErrorCode } from '../errors/index.js';

// ─── Integration State ────────────────────────────────────────────────────────

/** Lifecycle states of `RuntimeIntegration`. */
export enum IntegrationState {
  /** Constructed; not yet started. */
  IDLE = 'IDLE',
  /** `start()` is in-progress. */
  STARTING = 'STARTING',
  /** Fully started; conversation is running. */
  RUNNING = 'RUNNING',
  /** `stop()` or `shutdown()` is in-progress. */
  STOPPING = 'STOPPING',
  /** All components stopped; resources released. */
  STOPPED = 'STOPPED',
}

// ─── Dependencies ─────────────────────────────────────────────────────────────

/** Injected dependencies for `RuntimeIntegration`. */
export interface RuntimeIntegrationDependencies {
  /** Session identifier for log correlation and transport addressing. */
  readonly sessionId: SessionId;

  /** Media session that owns this call's lifecycle. */
  readonly mediaSession: IMediaSession;

  /** Audio engine driving inbound and outbound pipelines. */
  readonly audioEngine: IAudioEngine;

  /** Transport gateway used to send outbound audio and clear commands. */
  readonly transport: ITransportGateway;

  /** Realtime bridge between MediaSession and the AI provider. */
  readonly bridge: IRealtimeBridge;

  /** Inbound audio flow pipeline. */
  readonly inboundFlow: IInboundAudioFlow;

  /** Outbound audio flow pipeline. */
  readonly outboundFlow: IOutboundAudioFlow;

  /** Session supervisor for monitoring timeouts and disconnects. */
  readonly supervisor: ISessionSupervisor;

  /** Structured logger. */
  readonly logger: ILogger;
}

// ─── Public Interface ─────────────────────────────────────────────────────────

/**
 * Public contract for the top-level runtime integration.
 */
export interface IRuntimeIntegration {
  /** The current integration lifecycle state. */
  readonly state: IntegrationState;

  /** Session identifier associated with this integration. */
  readonly sessionId: SessionId;

  /**
   * Starts the full integration:
   * 1. Starts the audio engine.
   * 2. Connects the realtime bridge to the AI provider.
   * 3. Initialises and starts the media session.
   * 4. Activates the inbound and outbound audio flows.
   * 5. Starts the session supervisor.
   *
   * @throws {VoiceEngineError} if any component fails during start-up.
   */
  start(): Promise<void>;

  /**
   * Gracefully stops the integration:
   * 1. Stops the session supervisor.
   * 2. Stops inbound and outbound flows.
   * 3. Signals graceful session completion.
   * 4. Disconnects the realtime bridge.
   * 5. Stops the audio engine.
   *
   * @param reason - Human-readable reason for stopping.
   */
  stop(reason?: string): Promise<void>;

  /**
   * Forcibly tears down all components without waiting for graceful flushing.
   * Safe to call from any state, including STARTING or STOPPING.
   * Subsequent calls are no-ops.
   */
  shutdown(): void;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Production implementation of `IRuntimeIntegration`.
 */
export class RuntimeIntegration implements IRuntimeIntegration {
  private readonly _sessionId: SessionId;
  private readonly _mediaSession: IMediaSession;
  private readonly _audioEngine: IAudioEngine;
  private readonly _bridge: IRealtimeBridge;
  private readonly _inboundFlow: IInboundAudioFlow;
  private readonly _outboundFlow: IOutboundAudioFlow;
  private readonly _supervisor: ISessionSupervisor;
  private readonly _logger: ILogger;

  private _state: IntegrationState = IntegrationState.IDLE;

  constructor(deps: Readonly<RuntimeIntegrationDependencies>) {
    this._sessionId = deps.sessionId;
    this._mediaSession = deps.mediaSession;
    this._audioEngine = deps.audioEngine;
    this._bridge = deps.bridge;
    this._inboundFlow = deps.inboundFlow;
    this._outboundFlow = deps.outboundFlow;
    this._supervisor = deps.supervisor;
    this._logger = deps.logger.child({
      component: 'RuntimeIntegration',
      sessionId: deps.sessionId,
    });
  }

  // ─── Accessors ───────────────────────────────────────────────────────────────

  get state(): IntegrationState {
    return this._state;
  }

  get sessionId(): SessionId {
    return this._sessionId;
  }

  // ─── Lifecycle ────────────────────────────────────────────────────────────────

  /**
   * Starts all components in dependency order.
   *
   * Start order (each step awaited before the next):
   * 1. AudioEngine.start()
   * 2. RealtimeBridge.connect()
   * 3. MediaSession.initialize()
   * 4. MediaSession.start()
   * 5. InboundAudioFlow.start()
   * 6. OutboundAudioFlow.start()
   * 7. SessionSupervisor.start()
   */
  async start(): Promise<void> {
    this._assertState(IntegrationState.IDLE, 'start');
    this._state = IntegrationState.STARTING;

    this._logger.info('RuntimeIntegration starting');

    try {
      // Step 1 — Audio engine must be running before any pipeline operations.
      this._audioEngine.start();
      this._logger.debug('RuntimeIntegration: AudioEngine started');

      // Step 2 — Provider connection before media session initialises.
      await this._bridge.connect();
      this._logger.debug('RuntimeIntegration: RealtimeBridge connected');

      // Step 3 — Wire all media session components.
      await this._mediaSession.initialize();
      this._logger.debug('RuntimeIntegration: MediaSession initialised');

      // Step 4 — Begin the first conversational turn.
      await this._mediaSession.start();
      this._logger.debug('RuntimeIntegration: MediaSession started');

      // Step 5 — Begin receiving inbound audio from transport.
      this._inboundFlow.start();
      this._logger.debug('RuntimeIntegration: InboundAudioFlow started');

      // Step 6 — Begin forwarding AI audio to transport.
      this._outboundFlow.start();
      this._logger.debug('RuntimeIntegration: OutboundAudioFlow started');

      // Step 7 — Begin heartbeat and failure monitoring.
      this._supervisor.start();
      this._logger.debug('RuntimeIntegration: SessionSupervisor started');

    } catch (err) {
      this._logger.error('RuntimeIntegration: start failed, initiating shutdown', {
        error: String(err),
      });
      this.shutdown();
      throw err;
    }

    this._state = IntegrationState.RUNNING;
    this._logger.info('RuntimeIntegration running');
  }

  /**
   * Gracefully stops all components in reverse dependency order.
   *
   * Stop order:
   * 1. SessionSupervisor.stop()
   * 2. InboundAudioFlow.stop()
   * 3. OutboundAudioFlow.stop()
   * 4. MediaSession.complete(reason)
   * 5. RealtimeBridge.disconnect()
   * 6. AudioEngine.stop()
   *
   * @param reason - Human-readable reason for stopping.
   */
  async stop(reason = 'requested'): Promise<void> {
    if (
      this._state === IntegrationState.STOPPING ||
      this._state === IntegrationState.STOPPED
    ) {
      return;
    }

    this._state = IntegrationState.STOPPING;
    this._logger.info('RuntimeIntegration stopping', { reason });

    // Steps 1–3 are synchronous — stop before any async calls.
    this._supervisor.stop();
    this._inboundFlow.stop();
    this._outboundFlow.stop();

    // Step 4 — Gracefully complete the media session.
    try {
      await this._mediaSession.complete(reason);
    } catch (err) {
      this._logger.warn('RuntimeIntegration: mediaSession.complete() failed during stop', {
        error: String(err),
      });
    }

    // Step 5 — Close the provider connection.
    try {
      await this._bridge.disconnect();
    } catch (err) {
      this._logger.warn('RuntimeIntegration: bridge.disconnect() failed during stop', {
        error: String(err),
      });
    }

    // Step 6 — Signal end-of-stream on the audio pipelines.
    this._audioEngine.stop();

    this._state = IntegrationState.STOPPED;
    this._logger.info('RuntimeIntegration stopped');
  }

  /**
   * Forcibly tears down all components without waiting for graceful flushing.
   * Idempotent — safe to call from any state or multiple times.
   */
  shutdown(): void {
    if (this._state === IntegrationState.STOPPED) return;

    this._state = IntegrationState.STOPPING;
    this._logger.warn('RuntimeIntegration shutdown (forced)');

    // All synchronous teardown paths — no awaiting.
    try { this._supervisor.stop(); } catch { /* swallow */ }
    try { this._inboundFlow.stop(); } catch { /* swallow */ }
    try { this._outboundFlow.stop(); } catch { /* swallow */ }
    try { this._mediaSession.destroy(); } catch { /* swallow */ }
    try { this._bridge.disconnect().catch(() => undefined); } catch { /* swallow */ }
    try { this._audioEngine.destroy(); } catch { /* swallow */ }

    this._state = IntegrationState.STOPPED;
    this._logger.info('RuntimeIntegration shutdown complete');
  }

  // ─── Private Helpers ─────────────────────────────────────────────────────────

  private _assertState(expected: IntegrationState, method: string): void {
    if (this._state !== expected) {
      throw new VoiceEngineError(
        `RuntimeIntegration.${method}() called in state '${this._state}'; expected '${expected}'`,
        ErrorCode.PIPELINE_ABORTED,
        false,
        { sessionId: this._sessionId, currentState: this._state, expectedState: expected }
      );
    }
  }
}

/**
 * @module IntegrationFactory
 *
 * Factory for assembling a fully wired `RuntimeIntegration` from its
 * constituent dependencies.
 *
 * ## Responsibilities
 * - Receives all pre-constructed Voice Engine V2 components via
 *   `IntegrationFactoryInput`.
 * - Instantiates `RealtimeBridge`, `InboundAudioFlow`, `OutboundAudioFlow`,
 *   and `SessionSupervisor` with their correct dependencies.
 * - Returns a fully assembled `IRuntimeIntegration` ready to be started.
 *
 * ## Rules
 * - No OpenAI SDK imports.
 * - No Exotel protocol imports.
 * - No business logic, no CRM, no MongoDB.
 * - All construction is pure and synchronous — no side effects.
 * - Every component is injected; none are newed internally using
 *   provider-specific constructors.
 *
 * ## Usage
 * ```typescript
 * const integration = IntegrationFactory.create(input);
 * await integration.start();
 * // ... conversation runs ...
 * await integration.stop('goal_reached');
 * ```
 */

import type { ILogger } from '../logger/index.js';
import type { IMediaSession } from '../media/MediaSession.js';
import type { IAudioEngine } from '../audio-engine/AudioEngine.js';
import type { ITransportGateway } from '../transport/TransportGateway.js';
import type { IOpenAIRealtimeSession } from '../providers/openai/OpenAIRealtimeSession.js';
import type { SessionId } from '../types/index.js';
import type { OutboundAudioFormat } from './OutboundAudioFlow.js';
import type { SessionSupervisorConfig } from './SessionSupervisor.js';
import { RealtimeBridge } from './RealtimeBridge.js';
import { InboundAudioFlow } from './InboundAudioFlow.js';
import { OutboundAudioFlow } from './OutboundAudioFlow.js';
import { SessionSupervisor } from './SessionSupervisor.js';
import { RuntimeIntegration } from './RuntimeIntegration.js';
import type { IRuntimeIntegration } from './RuntimeIntegration.js';

// ─── Factory Input ────────────────────────────────────────────────────────────

/**
 * All pre-constructed Voice Engine V2 components required to assemble
 * a `RuntimeIntegration`.
 */
export interface IntegrationFactoryInput {
  /** Unique identifier for the call session. */
  readonly sessionId: SessionId;

  /** Media session that owns this call's lifecycle. */
  readonly mediaSession: IMediaSession;

  /** Audio engine driving inbound and outbound pipelines. */
  readonly audioEngine: IAudioEngine;

  /** Transport gateway for accepting and sending WebSocket messages. */
  readonly transport: ITransportGateway;

  /**
   * The AI provider realtime session.
   * Must not yet be connected — `RuntimeIntegration.start()` will connect it.
   */
  readonly providerSession: IOpenAIRealtimeSession;

  /** Structured logger, scoped to the application root or call context. */
  readonly logger: ILogger;

  /** Optional audio format for the outbound flow. */
  readonly outboundAudioFormat?: Partial<OutboundAudioFormat>;

  /** Optional supervisor tuning overrides. */
  readonly supervisorConfig?: Partial<SessionSupervisorConfig>;
}

// ─── Factory ──────────────────────────────────────────────────────────────────

/**
 * Assembles a `RuntimeIntegration` from its dependencies.
 *
 * All construction is pure and synchronous; no network or I/O calls are made.
 * Call `IRuntimeIntegration.start()` to initiate the live session.
 */
export const IntegrationFactory = Object.freeze({
  /**
   * Creates and wires a fully assembled `IRuntimeIntegration`.
   *
   * @param input - All required components and configuration.
   * @returns A ready-to-start `IRuntimeIntegration`.
   */
  create(input: Readonly<IntegrationFactoryInput>): IRuntimeIntegration {
    const {
      sessionId,
      mediaSession,
      audioEngine,
      transport,
      providerSession,
      logger,
      outboundAudioFormat,
      supervisorConfig,
    } = input;

    // Build the bridge — owns the provider ↔ media session connection.
    const bridge = new RealtimeBridge({
      providerSession,
      mediaSession,
      logger,
      sessionId,
    });

    // Build the inbound flow — Transport → AudioEngine → Bridge.
    const inboundFlow = new InboundAudioFlow({
      transport,
      mediaSession,
      audioEngine,
      bridge,
      logger,
      sessionId,
    });

    // Build the outbound flow — Bridge → AudioEngine → Transport.
    const outboundFlow = new OutboundAudioFlow({
      bridge,
      audioEngine,
      transport,
      sessionId,
      logger,
      config: outboundAudioFormat
        ? { audioFormat: { sampleRate: 8000, encoding: 'mulaw', ...outboundAudioFormat } }
        : undefined,
    });

    // Build the supervisor — monitors timeouts, disconnects, failures.
    const supervisor = new SessionSupervisor({
      mediaSession,
      bridge,
      logger,
      sessionId,
      config: supervisorConfig,
    });

    // Assemble the top-level integration.
    return new RuntimeIntegration({
      sessionId,
      mediaSession,
      audioEngine,
      transport,
      bridge,
      inboundFlow,
      outboundFlow,
      supervisor,
      logger,
    });
  },
});

/**
 * @module integration
 *
 * Public barrel export for the Voice Engine V2 Runtime Integration Layer.
 *
 * ## Modules exported
 *
 * | Module                | Purpose                                                   |
 * |-----------------------|-----------------------------------------------------------|
 * | `RealtimeBridge`      | Provider ↔ MediaSession audio channel + interrupt forward |
 * | `InboundAudioFlow`    | Transport → AudioEngine → Bridge pipeline                 |
 * | `OutboundAudioFlow`   | Bridge → AudioEngine → Transport pipeline                 |
 * | `SessionSupervisor`   | Timeout / disconnect / heartbeat monitoring               |
 * | `RuntimeIntegration`  | Top-level lifecycle owner (start / stop / shutdown)       |
 * | `IntegrationFactory`  | Assembles a fully wired RuntimeIntegration                |
 *
 * ## Entry Point
 * The canonical way to create a runtime integration is via `IntegrationFactory.create()`:
 *
 * ```typescript
 * import { IntegrationFactory } from '@voice-engine/integration';
 *
 * const integration = IntegrationFactory.create({
 *   sessionId,
 *   mediaSession,
 *   audioEngine,
 *   transport,
 *   providerSession,
 *   logger,
 * });
 *
 * await integration.start();
 * // ...
 * await integration.stop('goal_reached');
 * ```
 */

// ─── RealtimeBridge ───────────────────────────────────────────────────────────
export type {
  IRealtimeBridge,
  RealtimeBridgeDependencies,
  BridgeEvent,
  BridgeEventType,
  BridgeEventHandler,
  BridgeAudioReadyEvent,
  BridgeDisconnectedEvent,
  BridgeErrorEvent,
  BridgeSpeechDetectedEvent,
} from './RealtimeBridge.js';
export { RealtimeBridge } from './RealtimeBridge.js';

// ─── InboundAudioFlow ─────────────────────────────────────────────────────────
export type {
  IInboundAudioFlow,
  InboundAudioFlowDependencies,
  InboundAudioFlowConfig,
} from './InboundAudioFlow.js';
export { InboundAudioFlow } from './InboundAudioFlow.js';

// ─── OutboundAudioFlow ────────────────────────────────────────────────────────
export type {
  IOutboundAudioFlow,
  OutboundAudioFlowDependencies,
  OutboundAudioFlowConfig,
  OutboundAudioFormat,
} from './OutboundAudioFlow.js';
export { OutboundAudioFlow } from './OutboundAudioFlow.js';

// ─── SessionSupervisor ────────────────────────────────────────────────────────
export type {
  ISessionSupervisor,
  SessionSupervisorDependencies,
  SessionSupervisorConfig,
} from './SessionSupervisor.js';
export { SessionSupervisor } from './SessionSupervisor.js';

// ─── RuntimeIntegration ───────────────────────────────────────────────────────
export type {
  IRuntimeIntegration,
  RuntimeIntegrationDependencies,
} from './RuntimeIntegration.js';
export { RuntimeIntegration, IntegrationState } from './RuntimeIntegration.js';

// ─── IntegrationFactory ───────────────────────────────────────────────────────
export type { IntegrationFactoryInput } from './IntegrationFactory.js';
export { IntegrationFactory } from './IntegrationFactory.js';

