   * Null until the engine creates it upon WebSocket connection.
   */
  readonly mediaSession: Nullable<IMediaSession>;

  /**
   * Arbitrary caller-supplied metadata attached at session creation.
   * Frozen after construction.
   */
  readonly metadata: Readonly<SessionMetadata>;
}

// ─── Construction Input ───────────────────────────────────────────────────────

/**
 * All fields required to construct a `SessionContext`.
 * Supplied by `SessionFactory.createSession()`.
 */
export interface SessionContextInput {
  /** Unique session identifier. */
  readonly sessionId: SessionId;
  /** Initial call SID — may be null if not yet assigned. */
  readonly callSid: Nullable<CallSid>;
  /** Initial phone number — may be null if not yet known. */
  readonly phone: Nullable<string>;
  /** Campaign identifier. */
  readonly campaignId: CampaignId;
  /** Creation timestamp (Unix ms). */
  readonly createdAt: Timestamp;
  /** Bootstrap runtime for this session's engine. */
  readonly runtime: VoiceEngineRuntime;
  /** Wired voice engine instance. */
  readonly voiceEngine: IVoiceEngine;
  /** Transport gateway for this session. */
  readonly transportGateway: ITransportGateway;
  /** Per-call media session — null at creation time. */
  readonly mediaSession: Nullable<IMediaSession>;
  /** Optional caller metadata. */
  readonly metadata?: SessionMetadata;
}

// ─── Factory Function ─────────────────────────────────────────────────────────

/**
 * Constructs and freezes a `SessionContext` from the provided input.
 *
 * The returned object is passed through `Object.freeze` and may not be
 * mutated after this call. The `metadata` sub-object is also frozen.
 *
 * @param input - All required session fields.
 * @returns An immutable `SessionContext`.
 *
 * @throws {Error} if `sessionId` or `campaignId` are empty strings.
 *
 * @example
 * ```typescript
 * const ctx = createSessionContext({
 *   sessionId: 'sess-abc123',
 *   callSid: null,
 *   phone: null,
 *   campaignId: 'camp-xyz',
 *   createdAt: Date.now(),
 *   runtime,
 *   voiceEngine,
 *   transportGateway,
 *   mediaSession: null,
 * });
 * ```
 */
export function createSessionContext(
  input: SessionContextInput
): Readonly<SessionContext> {
  if (!input.sessionId.trim()) {
    throw new Error('SessionContext: sessionId must be a non-empty string.');
  }
  if (!input.campaignId.trim()) {
    throw new Error('SessionContext: campaignId must be a non-empty string.');
  }

  const ctx: SessionContext = {
    sessionId:        input.sessionId,
    callSid:          input.callSid,
    phone:            input.phone,
    campaignId:       input.campaignId,
    createdAt:        input.createdAt,
    runtime:          input.runtime,
    voiceEngine:      input.voiceEngine,
    transportGateway: input.transportGateway,
    mediaSession:     input.mediaSession,
    metadata:         Object.freeze({ ...(input.metadata ?? {}) }),
  };

  return Object.freeze(ctx);
}

/**
 * @module V2SessionCoordinator
 *
 * The single, authoritative entry point for creating and managing
 * Voice Engine V2 call sessions during the V1→V2 migration period.
 *
 * ## Responsibility
 * `V2SessionCoordinator` owns the full lifecycle of a V2 session:
 * creation, lookup-index attachment, retrieval, destruction, and
 * periodic expiry cleanup. It delegates all storage concerns to
 * `SessionRegistry` and all construction concerns to `SessionFactory`.
 *
 * ## What it does NOT do
 * - No OpenAI calls.
 * - No Exotel calls.
 * - No transport or WebSocket logic.
 * - No audio processing.
 *
 * ## Thread Safety
 * Node.js is single-threaded. All methods are synchronous or sequential
 * `async/await`. No locking is required.
 *
 * ## Rules
 * - No OpenAI imports.
 * - No Exotel imports.
 * - No transport logic.
 * - No WebSocket logic.
 * - Owns ONLY `SessionRegistry`.
 * - All dependencies injected through the constructor.
 */

import type { ILogger } from '../logger/index.js';
import type { SessionId, CallSid, Nullable } from '../types/index.js';
import type { ISessionRegistry } from './SessionRegistry.js';
import type { ISessionFactory, CreateSessionParams } from './SessionFactory.js';
import type { SessionContext } from './SessionContext.js';

// ─── Options ──────────────────────────────────────────────────────────────────

/**
 * Configuration options for `V2SessionCoordinator`.
 */
export interface V2SessionCoordinatorOptions {
  /**
   * Maximum session age before it is eligible for cleanup.
   * Defaults to 3 600 000 ms (1 hour).
   */
  readonly maxSessionAgeMs?: number;
}

// ─── Public Interface ─────────────────────────────────────────────────────────

/**
 * Public contract for the V2 session coordinator.
 */
export interface IV2SessionCoordinator {
  /**
   * Creates a new V2 call session.
   *
   * Internally calls `SessionFactory.createSession()` to construct all
   * V2 engine dependencies, then registers the result in `SessionRegistry`.
   *
   * @param params - Session creation parameters (campaignId required; phone
   *                 and callSid are optional at creation time).
   * @returns The frozen `SessionContext` for the new session.
   *
   * @throws {Error} if session construction fails.
   */
  createSession(params: CreateSessionParams): Promise<Readonly<SessionContext>>;

  /**
   * Associates a telephony call SID with an existing session.
   *
   * Updates the `callSid` lookup index in `SessionRegistry` so that
   * future calls to `getSession({ callSid })` resolve correctly.
   *
   * @param sessionId - The session to update.
   * @param callSid   - The call SID returned by the telephony provider.
   *
   * @throws {Error} if `sessionId` is not registered.
   */
  attachCallSid(sessionId: SessionId, callSid: CallSid): void;

  /**
   * Associates a phone number with an existing session.
   *
   * Updates the `phone` lookup index in `SessionRegistry` so that
   * future calls to `getSession({ phone })` resolve correctly.
   *
   * @param sessionId - The session to update.
   * @param phone     - The E.164 phone number of the remote party.
   *
   * @throws {Error} if `sessionId` is not registered.
   */
  attachPhone(sessionId: SessionId, phone: string): void;

  /**
   * Retrieves a session by one of several lookup keys.
   *
   * Exactly one lookup key should be provided. If multiple are provided,
   * `sessionId` takes precedence over `callSid`, which takes precedence
   * over `phone`.
   *
   * @returns The `SessionContext`, or `null` if no match is found.
   */
  getSession(lookup: SessionLookup): Nullable<Readonly<SessionContext>>;

  /**
   * Destroys a session and releases all associated resources.
   *
   * Steps performed:
   * 1. Retrieves the context from the registry.
   * 2. Calls `voiceEngine.destroy()`.
   * 3. Unregisters the session from `SessionRegistry`.
   *
   * No-op if the session is not found.
   *
   * @param sessionId - The session to destroy.
   */
  destroySession(sessionId: SessionId): void;

  /**
   * Removes all sessions older than the configured `maxSessionAgeMs`.
   *
   * Calls `voiceEngine.destroy()` on each removed session before
   * unregistering it from the registry.
   *
   * @returns The number of sessions removed.
   */
  cleanupExpiredSessions(): number;

  /**
   * Returns the number of active sessions currently held in the registry.
   */
  readonly activeSessionCount: number;
}

// ─── Lookup Types ─────────────────────────────────────────────────────────────

/**
 * Identifies a session for retrieval.
 * Provide exactly one field. Priority: sessionId > callSid > phone.
 */
export interface SessionLookup {
  readonly sessionId?: SessionId;
  readonly callSid?: CallSid;
  readonly phone?: string;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Production implementation of `IV2SessionCoordinator`.
 *
 * Construct via `MigrationFactory.createCoordinator()`.
 */
export class V2SessionCoordinator implements IV2SessionCoordinator {
  private readonly _log: ILogger;
  private readonly _registry: ISessionRegistry;
  private readonly _factory: ISessionFactory;
  private readonly _maxSessionAgeMs: number;

  /**
   * @param registry - The session registry this coordinator owns.
   * @param factory  - Factory used to construct new sessions.
   * @param logger   - Logger; will be child-bound to this component.
   * @param options  - Optional configuration overrides.
   */
  constructor(
    registry: ISessionRegistry,
    factory: ISessionFactory,
    logger: ILogger,
    options: V2SessionCoordinatorOptions = {}
  ) {
    this._registry       = registry;
    this._factory        = factory;
    this._log            = logger.child({ component: 'V2SessionCoordinator' });
    this._maxSessionAgeMs = options.maxSessionAgeMs ?? 60 * 60 * 1000; // 1 hour
  }

  // ─── IV2SessionCoordinator ──────────────────────────────────────────────────

  async createSession(
    params: CreateSessionParams
  ): Promise<Readonly<SessionContext>> {
    this._log.info('Creating V2 session', {
      campaignId: params.campaignId,
      phone:      params.phone ?? null,
      callSid:    params.callSid ?? null,
    });

    const context = await this._factory.createSession(params);
    this._registry.register(context);

    if (context.callSid) {
      this._registry.updateCallSid(context.sessionId, context.callSid);
    }

    if (context.phone) {
      this._registry.updatePhone(context.sessionId, context.phone);
    }

    this._log.info('V2 session created', {
      sessionId:  context.sessionId,
      campaignId: context.campaignId,
    });

    return context;
  }

  attachCallSid(sessionId: SessionId, callSid: CallSid): void {
    this._log.debug('Attaching callSid', { sessionId, callSid });
    this._registry.updateCallSid(sessionId, callSid);
  }

  attachPhone(sessionId: SessionId, phone: string): void {
    this._log.debug('Attaching phone', { sessionId, phone });
    this._registry.updatePhone(sessionId, phone);
  }

  getSession(lookup: SessionLookup): Nullable<Readonly<SessionContext>> {
    if (lookup.sessionId !== undefined) {
      return this._registry.get(lookup.sessionId);
    }
    if (lookup.callSid !== undefined) {
      return this._registry.getByCallSid(lookup.callSid);
    }
    if (lookup.phone !== undefined) {
      return this._registry.getByPhone(lookup.phone);
    }

    this._log.warn('getSession called with no lookup key');
    return null;
  }

  destroySession(sessionId: SessionId): void {
    const ctx = this._registry.get(sessionId);
    if (!ctx) {
      this._log.warn('destroySession: session not found', { sessionId });
      return;
    }

    this._log.info('Destroying V2 session', { sessionId });

    try {
      ctx.voiceEngine.destroy();
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      this._log.error('Error destroying voice engine', { sessionId, error: message });
    }

    this._registry.unregister(sessionId);
    this._log.info('V2 session destroyed', { sessionId });
  }

  cleanupExpiredSessions(): number {
    this._log.debug('Running expired session cleanup', {
      maxSessionAgeMs: this._maxSessionAgeMs,
      activeSessions:  this._registry.count(),
    });

    const cutoff = Date.now() - this._maxSessionAgeMs;

    // Collect expired sessions first to avoid mutating the registry
    // while iterating (unregister sweeps indices during unregister).
    const expired = this._registry
      .list()
      .filter((ctx) => ctx.createdAt < cutoff)
      .map((ctx) => ctx.sessionId);

    for (const sessionId of expired) {
      this.destroySession(sessionId);
    }

    if (expired.length > 0) {
      this._log.info('Expired sessions cleaned up', {
        removed:   expired.length,
        remaining: this._registry.count(),
      });
    }

    return expired.length;
  }

  get activeSessionCount(): number {
    return this._registry.count();
  }
}

/**
 * @module SessionFactory
 *
 * Dependency-injected factory for constructing Voice Engine V2 session contexts.
 *
 * ## Responsibility
 * `SessionFactory` is the single place where a `VoiceEngine` instance and a
 * `TransportGateway` are assembled into a `SessionContext`. It delegates all
 * engine construction to `VoiceEngineFactory` and gateway construction to
 * `TransportFactory`. It performs no business logic of its own.
 *
 * ## mediaSession
 * `mediaSession` in the returned `SessionContext` is always `null` at
 * construction time. The engine creates per-call `MediaSession` objects
 * internally when a WebSocket connection is accepted by the gateway.
 *
 * ## Rules
 * - No OpenAI imports.
 * - No Exotel imports.
 * - No transport logic beyond calling `TransportFactory.createGateway()`.
 * - No WebSocket logic.
 * - No business logic.
 * - All dependencies injected through the constructor.
 */

import type { ILogger } from '../logger/index.js';
import type { IVoiceEngineFactory } from '../engine/VoiceEngineFactory.js';
import type { ITransportFactory } from '../transport/TransportFactory.js';
import type { BootstrapOptions } from '../bootstrap/Bootstrap.js';
import type { SessionId, CallSid, CampaignId, Nullable } from '../types/index.js';
import { createVoiceEngineRuntime } from '../bootstrap/Bootstrap.js';
import { createSessionContext } from './SessionContext.js';
import type { SessionContext, SessionMetadata } from './SessionContext.js';

// ─── Session ID ───────────────────────────────────────────────────────────────

let _sessionCounter = 0;

/**
 * Generates a lexicographically sortable, collision-resistant session ID.
 * Format: `v2s-{timestamp}-{counter}`.
 */
function generateSessionId(): SessionId {
  return `v2s-${Date.now()}-${(++_sessionCounter).toString().padStart(6, '0')}`;
}

// ─── Creation Parameters ──────────────────────────────────────────────────────

/**
 * Parameters accepted by `ISessionFactory.createSession()`.
 */
export interface CreateSessionParams {
  /**
   * Campaign identifier — required.
   * Must be a non-empty string.
   */
  readonly campaignId: CampaignId;

  /**
   * Initial call SID.
   * May be omitted when the outbound call has not been placed yet.
   * Provide this when the call SID is known at session creation time.
   */
  readonly callSid?: Nullable<CallSid>;

  /**
   * E.164 phone number of the remote party.
   * May be omitted when placing an outbound call before the SID is assigned.
   */
  readonly phone?: Nullable<string>;

  /**
   * Optional bootstrap options forwarded to the `VoiceEngineFactory`.
   * Use to inject provider overrides (e.g. in test environments).
   */
  readonly bootstrapOptions?: BootstrapOptions;

  /**
   * Arbitrary metadata to attach to the session context.
   */
  readonly metadata?: SessionMetadata;
}

// ─── Public Interface ─────────────────────────────────────────────────────────

/**
 * Public contract for the session factory.
 */
export interface ISessionFactory {
  /**
   * Constructs a new `SessionContext` containing a fully wired `VoiceEngine`
   * and `TransportGateway`.
   *
   * The returned context is frozen and ready to be registered by
   * `V2SessionCoordinator`. The `mediaSession` field is always `null`
   * until a WebSocket connection is established.
   *
   * @param params - Session creation parameters.
   * @returns A frozen `SessionContext`.
   *
   * @throws {Error} if `params.campaignId` is empty.
   * @throws {Error} if engine construction fails.
   */
  createSession(params: CreateSessionParams): Promise<Readonly<SessionContext>>;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Production implementation of `ISessionFactory`.
 *
 * Construct via `MigrationFactory.createSessionFactory()`.
 */
export class SessionFactory implements ISessionFactory {
  private readonly _log: ILogger;
  private readonly _engineFactory: IVoiceEngineFactory;
  private readonly _transportFactory: ITransportFactory;

  /**
   * @param engineFactory    - Factory for constructing `IVoiceEngine` instances.
   * @param transportFactory - Factory for constructing `ITransportGateway` instances.
   * @param logger           - Logger; will be child-bound to this component.
   */
  constructor(
    engineFactory: IVoiceEngineFactory,
    transportFactory: ITransportFactory,
    logger: ILogger
  ) {
    this._engineFactory    = engineFactory;
    this._transportFactory = transportFactory;
    this._log              = logger.child({ component: 'SessionFactory' });
  }

  // ─── ISessionFactory ────────────────────────────────────────────────────────

  async createSession(params: CreateSessionParams): Promise<Readonly<SessionContext>> {
    const { campaignId } = params;

    if (!campaignId.trim()) {
      throw new Error('SessionFactory: campaignId must be a non-empty string.');
    }

    const sessionId = generateSessionId();

    this._log.debug('Building session dependencies', { sessionId, campaignId });

    // ── Step 1: Build the bootstrap runtime ───────────────────────────────────
    //
    // We build the runtime explicitly so the SessionContext can hold a direct
    // reference to it. The VoiceEngineFactory also builds its own internal
    // runtime copy via bootstrapOptions — both read the same environment
    // variables and produce equivalent, independent frozen objects.
    const bootstrapOptions = params.bootstrapOptions ?? {};
    const runtime = createVoiceEngineRuntime(bootstrapOptions);

    // ── Step 2: Create the VoiceEngine ────────────────────────────────────────
    //
    // autoStart: false — the caller (V2SessionCoordinator) is responsible for
    // calling initialize() and start() at the appropriate time. This keeps the
    // factory non-blocking and avoids premature network I/O during construction.
    const voiceEngine = await this._engineFactory.create({
      bootstrapOptions,
      autoStart: false,
    });

    // ── Step 3: Create the TransportGateway ───────────────────────────────────
    //
    // The gateway is created without any adapters registered. The integration
    // layer (e.g. ExotelAdapter) registers itself before the gateway starts
    // accepting connections.
    const transportGateway = this._transportFactory.createGateway();

    // ── Step 4: Assemble and freeze the SessionContext ────────────────────────
    const context = createSessionContext({
      sessionId,
      callSid:          params.callSid ?? null,
      phone:            params.phone   ?? null,
      campaignId,
      createdAt:        Date.now(),
      runtime,
      voiceEngine,
      transportGateway,
      mediaSession:     null,
      metadata:         params.metadata ?? {},
    });

    this._log.info('SessionContext created', {
      sessionId,
      campaignId,
      callSid: context.callSid,
      phone:   context.phone,
    });

    return context;
  }
}

/**
 * @module MigrationFactory
 *
 * Dependency-injection entry point for the V2 migration layer.
 *
 * ## Purpose
 * `MigrationFactory` is the single place in the application where all
 * migration-layer dependencies (registry, session factory, coordinator) are
 * assembled. It wires together existing Voice Engine factories with the new
 * migration-specific classes and returns a fully configured
 * `V2SessionCoordinator` ready for use.
 *
 * ## Usage
 * Call `MigrationFactory.create(deps)` once during application startup.
 * Hold the returned coordinator as a process-level singleton.
 *
 * ## Rules
 * - No OpenAI imports.
 * - No Exotel imports.
 * - No transport logic.
 * - No WebSocket logic.
 * - No business logic — wiring only.
 * - All dependencies injected through `MigrationFactoryDependencies`.
 */

import type { ILogger } from '../logger/index.js';
import type { IVoiceEngineFactory } from '../engine/VoiceEngineFactory.js';
import type { ITransportFactory } from '../transport/TransportFactory.js';
import { SessionRegistry } from './SessionRegistry.js';
import type { ISessionRegistry } from './SessionRegistry.js';
import { SessionFactory } from './SessionFactory.js';
import type { ISessionFactory } from './SessionFactory.js';
import { V2SessionCoordinator } from './V2SessionCoordinator.js';
import type { IV2SessionCoordinator, V2SessionCoordinatorOptions } from './V2SessionCoordinator.js';

// ─── Dependencies ─────────────────────────────────────────────────────────────

/**
 * All external dependencies required by `MigrationFactory`.
 *
 * These must be fully constructed and ready before calling
 * `MigrationFactory.create()`.
 */
export interface MigrationFactoryDependencies {
  /**
   * Factory for constructing `IVoiceEngine` instances.
   * Typically `new VoiceEngineFactory()` from the engine module.
   */
  readonly voiceEngineFactory: IVoiceEngineFactory;

  /**
   * Factory for constructing `ITransportGateway` instances.
   * Typically `new TransportFactory(logger)` from the transport module.
   */
  readonly transportFactory: ITransportFactory;

  /**
   * Structured logger scoped to the migration layer.
   * All child components receive child-bound instances.
   */
  readonly logger: ILogger;
}

// ─── Options ──────────────────────────────────────────────────────────────────

/**
 * Optional configuration forwarded to the `V2SessionCoordinator`.
 */
export interface MigrationFactoryOptions {
  /**
   * Coordinator-level options (e.g. `maxSessionAgeMs`).
   */
  readonly coordinator?: V2SessionCoordinatorOptions;
}

// ─── Public Interface ─────────────────────────────────────────────────────────

/**
 * Public contract for the migration factory.
 */
export interface IMigrationFactory {
  /**
   * Constructs and returns a fully wired `IV2SessionCoordinator`.
   *
   * @returns A ready-to-use coordinator.
   */
  createCoordinator(): IV2SessionCoordinator;

  /**
   * Constructs and returns the underlying `ISessionRegistry`.
   *
   * Exposed for consumers that need direct registry access (e.g. health
   * checks, admin endpoints). In production use, prefer the coordinator.
   *
   * @returns A new `ISessionRegistry` instance.
   */
  createRegistry(): ISessionRegistry;

  /**
   * Constructs and returns the underlying `ISessionFactory`.
   *
   * Exposed for testing. In production use, prefer the coordinator.
   *
   * @returns A new `ISessionFactory` instance.
   */
  createSessionFactory(): ISessionFactory;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Production implementation of `IMigrationFactory`.
 *
 * ```typescript
 * const factory = new MigrationFactory(deps, options);
 * const coordinator = factory.createCoordinator();
 *
 * // Application code:
 * const session = await coordinator.createSession({ campaignId: 'camp-1', phone: '+917000000001' });
 * coordinator.attachCallSid(session.sessionId, exotelCallSid);
 * ```
 */
export class MigrationFactory implements IMigrationFactory {
  private readonly _deps: MigrationFactoryDependencies;
  private readonly _options: MigrationFactoryOptions;

  constructor(
    deps: MigrationFactoryDependencies,
    options: MigrationFactoryOptions = {}
  ) {
    this._deps    = deps;
    this._options = options;
  }

  // ─── IMigrationFactory ──────────────────────────────────────────────────────

  createCoordinator(): IV2SessionCoordinator {
    const registry = this.createRegistry();
    const factory  = this.createSessionFactory();

    return new V2SessionCoordinator(
      registry,
      factory,
      this._deps.logger,
      this._options.coordinator ?? {}
    );
  }

  createRegistry(): ISessionRegistry {
    return new SessionRegistry(this._deps.logger);
  }

  createSessionFactory(): ISessionFactory {
    return new SessionFactory(
      this._deps.voiceEngineFactory,
      this._deps.transportFactory,
      this._deps.logger
    );
  }
}

// ─── Convenience Function ─────────────────────────────────────────────────────

/**
 * Top-level convenience function.
 *
 * Equivalent to `new MigrationFactory(deps, options).createCoordinator()`.
 *
 * Call once at process startup and hold the result as a module-level constant.
 *
 * @param deps    - Required external dependencies.
 * @param options - Optional configuration overrides.
 * @returns A fully wired `IV2SessionCoordinator`.
 *
 * @example
 * ```typescript
 * import { VoiceEngineFactory } from '../engine/VoiceEngineFactory.js';
 * import { TransportFactory }   from '../transport/TransportFactory.js';
 * import { createV2SessionCoordinator } from './migration/index.js';
 *
 * const coordinator = createV2SessionCoordinator({
 *   voiceEngineFactory: new VoiceEngineFactory(),
 *   transportFactory:   new TransportFactory(logger),
 *   logger,
 * });
 *
 * // On outbound call initiation:
 * const session = await coordinator.createSession({ campaignId, phone });
 * coordinator.attachCallSid(session.sessionId, exotelCallSid);
 *
 * // On session end:
 * coordinator.destroySession(session.sessionId);
 * ```
 */
export function createV2SessionCoordinator(
  deps: MigrationFactoryDependencies,
  options: MigrationFactoryOptions = {}
): IV2SessionCoordinator {
  return new MigrationFactory(deps, options).createCoordinator();
}

/**
 * @module migration
 *
 * Voice Engine V2 Migration Layer — public API.
 *
 * ## Purpose
 * This module exposes the ONLY entry points needed by the rest of the
 * application to create, manage, and look up V2 call sessions during
 * the V1→V2 migration period.
 *
 * ## Quick-start
 * ```typescript
 * import {
 *   createV2SessionCoordinator,
 *   type IV2SessionCoordinator,
 *   type SessionContext,
 * } from './voice-engine/migration/index.js';
 *
 * import { VoiceEngineFactory } from './voice-engine/engine/VoiceEngineFactory.js';
 * import { TransportFactory }   from './voice-engine/transport/TransportFactory.js';
 *
 * // 1. Create once at process startup:
 * const coordinator: IV2SessionCoordinator = createV2SessionCoordinator({
 *   voiceEngineFactory: new VoiceEngineFactory(),
 *   transportFactory:   new TransportFactory(logger),
 *   logger,
 * });
 *
 * // 2. On every outbound call:
 * const session: SessionContext = await coordinator.createSession({
 *   campaignId: 'camp-abc',
 *   phone: '+917000000001',
 * });
 *
 * // 3. After Exotel returns the callSid:
 * coordinator.attachCallSid(session.sessionId, exotelCallSid);
 *
 * // 4. On call end:
 * coordinator.destroySession(session.sessionId);
 *
 * // 5. Periodic cleanup (e.g. in a setInterval):
 * coordinator.cleanupExpiredSessions();
 * ```
 *
 * ## What is NOT exported
 * - `SessionRegistry` implementation (use `ISessionRegistry` interface only).
 * - `SessionFactory` implementation (use `ISessionFactory` interface only).
 * - `V2SessionCoordinator` implementation (use `IV2SessionCoordinator` interface only).
 * - `MigrationFactory` implementation (use `createV2SessionCoordinator()` instead).
 *
 * ## Rules
 * - No OpenAI imports.
 * - No Exotel imports.
 * - No transport logic.
 * - No WebSocket logic.
 */

// ─── SessionContext ────────────────────────────────────────────────────────────

export type {
  SessionContext,
  SessionContextInput,
  SessionMetadata,
} from './SessionContext.js';

export { createSessionContext } from './SessionContext.js';

// ─── SessionRegistry ──────────────────────────────────────────────────────────

export type { ISessionRegistry } from './SessionRegistry.js';

export { SessionRegistry } from './SessionRegistry.js';

// ─── SessionFactory ───────────────────────────────────────────────────────────

export type {
  ISessionFactory,
  CreateSessionParams,
} from './SessionFactory.js';

export { SessionFactory } from './SessionFactory.js';

// ─── V2SessionCoordinator ─────────────────────────────────────────────────────

export type {
  IV2SessionCoordinator,
  V2SessionCoordinatorOptions,
  SessionLookup,
