    48→  STARTING = 'STARTING',
    49→  /** Fully started; conversation is running. */
    50→  RUNNING = 'RUNNING',
    51→  /** `stop()` or `shutdown()` is in-progress. */
    52→  STOPPING = 'STOPPING',
    53→  /** All components stopped; resources released. */
    54→  STOPPED = 'STOPPED',
    55→}
    56→
    57→// ─── Dependencies ─────────────────────────────────────────────────────────────
    58→
    59→/** Injected dependencies for `RuntimeIntegration`. */
    60→export interface RuntimeIntegrationDependencies {
    61→  /** Session identifier for log correlation and transport addressing. */
    62→  readonly sessionId: SessionId;
    63→
    64→  /** Media session that owns this call's lifecycle. */
    65→  readonly mediaSession: IMediaSession;
    66→
    67→  /** Audio engine driving inbound and outbound pipelines. */
    68→  readonly audioEngine: IAudioEngine;
    69→
    70→  /** Transport gateway used to send outbound audio and clear commands. */
    71→  readonly transport: ITransportGateway;
    72→
    73→  /** Realtime bridge between MediaSession and the AI provider. */
    74→  readonly bridge: IRealtimeBridge;
    75→
    76→  /** Inbound audio flow pipeline. */
    77→  readonly inboundFlow: IInboundAudioFlow;
    78→
    79→  /** Outbound audio flow pipeline. */
    80→  readonly outboundFlow: IOutboundAudioFlow;
    81→
    82→  /** Session supervisor for monitoring timeouts and disconnects. */
    83→  readonly supervisor: ISessionSupervisor;
    84→
    85→  /** Structured logger. */
    86→  readonly logger: ILogger;
    87→}
    88→
    89→// ─── Public Interface ─────────────────────────────────────────────────────────
    90→
    91→/**
    92→ * Public contract for the top-level runtime integration.
    93→ */
    94→export interface IRuntimeIntegration {
    95→  /** The current integration lifecycle state. */
    96→  readonly state: IntegrationState;
    97→
    98→  /** Session identifier associated with this integration. */
    99→  readonly sessionId: SessionId;
   100→
   101→  /**
   102→   * Starts the full integration:
   103→   * 1. Starts the audio engine.
   104→   * 2. Connects the realtime bridge to the AI provider.
   105→   * 3. Initialises and starts the media session.
   106→   * 4. Activates the inbound and outbound audio flows.
   107→   * 5. Starts the session supervisor.
   108→   *
   109→   * @throws {VoiceEngineError} if any component fails during start-up.
   110→   */
   111→  start(): Promise<void>;
   112→
   113→  /**
   114→   * Gracefully stops the integration:
   115→   * 1. Stops the session supervisor.
   116→   * 2. Stops inbound and outbound flows.
   117→   * 3. Signals graceful session completion.
   118→   * 4. Disconnects the realtime bridge.
   119→   * 5. Stops the audio engine.
   120→   *
   121→   * @param reason - Human-readable reason for stopping.
   122→   */
   123→  stop(reason?: string): Promise<void>;
   124→
   125→  /**
   126→   * Forcibly tears down all components without waiting for graceful flushing.
   127→   * Safe to call from any state, including STARTING or STOPPING.
   128→   * Subsequent calls are no-ops.
   129→   */
   130→  shutdown(): void;
   131→}
   132→
   133→// ─── Implementation ───────────────────────────────────────────────────────────
   134→
   135→/**
   136→ * Production implementation of `IRuntimeIntegration`.
   137→ */
   138→export class RuntimeIntegration implements IRuntimeIntegration {
   139→  private readonly _sessionId: SessionId;
   140→  private readonly _mediaSession: IMediaSession;
   141→  private readonly _audioEngine: IAudioEngine;
   142→  private readonly _bridge: IRealtimeBridge;
   143→  private readonly _inboundFlow: IInboundAudioFlow;
   144→  private readonly _outboundFlow: IOutboundAudioFlow;
   145→  private readonly _supervisor: ISessionSupervisor;
   146→  private readonly _logger: ILogger;
   147→
   148→  private _state: IntegrationState = IntegrationState.IDLE;
   149→
   150→  constructor(deps: Readonly<RuntimeIntegrationDependencies>) {
   151→    this._sessionId = deps.sessionId;
   152→    this._mediaSession = deps.mediaSession;
   153→    this._audioEngine = deps.audioEngine;
   154→    this._bridge = deps.bridge;
   155→    this._inboundFlow = deps.inboundFlow;
   156→    this._outboundFlow = deps.outboundFlow;
   157→    this._supervisor = deps.supervisor;
   158→    this._logger = deps.logger.child({
   159→      component: 'RuntimeIntegration',
   160→      sessionId: deps.sessionId,
   161→    });
   162→  }
   163→
   164→  // ─── Accessors ───────────────────────────────────────────────────────────────
   165→
   166→  get state(): IntegrationState {
   167→    return this._state;
   168→  }
   169→
   170→  get sessionId(): SessionId {
   171→    return this._sessionId;
   172→  }
   173→
   174→  // ─── Lifecycle ────────────────────────────────────────────────────────────────
   175→
   176→  /**
   177→   * Starts all components in dependency order.
   178→   *
   179→   * Start order (each step awaited before the next):
   180→   * 1. AudioEngine.start()
   181→   * 2. RealtimeBridge.connect()
   182→   * 3. MediaSession.initialize()
   183→   * 4. MediaSession.start()
   184→   * 5. InboundAudioFlow.start()
   185→   * 6. OutboundAudioFlow.start()
   186→   * 7. SessionSupervisor.start()
   187→   */
   188→  async start(): Promise<void> {
   189→    this._assertState(IntegrationState.IDLE, 'start');
   190→    this._state = IntegrationState.STARTING;
   191→
   192→    this._logger.info('RuntimeIntegration starting');
   193→
   194→    try {
   195→      // Step 1 — Audio engine must be running before any pipeline operations.
   196→      this._audioEngine.start();
   197→      this._logger.debug('RuntimeIntegration: AudioEngine started');
   198→
   199→      // Step 2 — Provider connection before media session initialises.
   200→      await this._bridge.connect();
   201→      this._logger.debug('RuntimeIntegration: RealtimeBridge connected');
   202→
   203→      // Step 3 — Wire all media session components.
   204→      await this._mediaSession.initialize();
   205→      this._logger.debug('RuntimeIntegration: MediaSession initialised');
   206→
   207→      // Step 4 — Begin the first conversational turn.
   208→      await this._mediaSession.start();
   209→      this._logger.debug('RuntimeIntegration: MediaSession started');
   210→
   211→      // Step 5 — Begin receiving inbound audio from transport.
   212→      this._inboundFlow.start();
   213→      this._logger.debug('RuntimeIntegration: InboundAudioFlow started');
   214→
   215→      // Step 6 — Begin forwarding AI audio to transport.
   216→      this._outboundFlow.start();
   217→      this._logger.debug('RuntimeIntegration: OutboundAudioFlow started');
   218→
   219→      // Step 7 — Begin heartbeat and failure monitoring.
   220→      this._supervisor.start();
   221→      this._logger.debug('RuntimeIntegration: SessionSupervisor started');
   222→
   223→    } catch (err) {
   224→      this._logger.error('RuntimeIntegration: start failed, initiating shutdown', {
   225→        error: String(err),
   226→      });
   227→      this.shutdown();
   228→      throw err;
   229→    }
   230→
   231→    this._state = IntegrationState.RUNNING;
   232→    this._logger.info('RuntimeIntegration running');
   233→  }
   234→
   235→  /**
   236→   * Gracefully stops all components in reverse dependency order.
   237→   *
   238→   * Stop order:
   239→   * 1. SessionSupervisor.stop()
   240→   * 2. InboundAudioFlow.stop()
   241→   * 3. OutboundAudioFlow.stop()
   242→   * 4. MediaSession.complete(reason)
   243→   * 5. RealtimeBridge.disconnect()
   244→   * 6. AudioEngine.stop()
   245→   *
   246→   * @param reason - Human-readable reason for stopping.
   247→   */
   248→  async stop(reason = 'requested'): Promise<void> {
   249→    if (
   250→      this._state === IntegrationState.STOPPING ||
   251→      this._state === IntegrationState.STOPPED
   252→    ) {
   253→      return;
   254→    }
   255→
   256→    this._state = IntegrationState.STOPPING;
   257→    this._logger.info('RuntimeIntegration stopping', { reason });
   258→
   259→    // Steps 1–3 are synchronous — stop before any async calls.
   260→    this._supervisor.stop();
   261→    this._inboundFlow.stop();
   262→    this._outboundFlow.stop();
   263→
   264→    // Step 4 — Gracefully complete the media session.
   265→    try {
   266→      await this._mediaSession.complete(reason);
   267→    } catch (err) {
   268→      this._logger.warn('RuntimeIntegration: mediaSession.complete() failed during stop', {
   269→        error: String(err),
   270→      });
   271→    }
   272→
   273→    // Step 5 — Close the provider connection.
   274→    try {
   275→      await this._bridge.disconnect();
   276→    } catch (err) {
   277→      this._logger.warn('RuntimeIntegration: bridge.disconnect() failed during stop', {
   278→        error: String(err),
   279→      });
   280→    }
   281→
   282→    // Step 6 — Signal end-of-stream on the audio pipelines.
   283→    this._audioEngine.stop();
   284→
   285→    this._state = IntegrationState.STOPPED;
   286→    this._logger.info('RuntimeIntegration stopped');
   287→  }
   288→
   289→  /**
   290→   * Forcibly tears down all components without waiting for graceful flushing.
   291→   * Idempotent — safe to call from any state or multiple times.
   292→   */
   293→  shutdown(): void {
   294→    if (this._state === IntegrationState.STOPPED) return;
   295→
   296→    this._state = IntegrationState.STOPPING;
   297→    this._logger.warn('RuntimeIntegration shutdown (forced)');
   298→
   299→    // All synchronous teardown paths — no awaiting.
   300→    try { this._supervisor.stop(); } catch { /* swallow */ }
   301→    try { this._inboundFlow.stop(); } catch { /* swallow */ }
   302→    try { this._outboundFlow.stop(); } catch { /* swallow */ }
   303→    try { this._mediaSession.destroy(); } catch { /* swallow */ }
   304→    try { this._bridge.disconnect().catch(() => undefined); } catch { /* swallow */ }
   305→    try { this._audioEngine.destroy(); } catch { /* swallow */ }
   306→
   307→    this._state = IntegrationState.STOPPED;
   308→    this._logger.info('RuntimeIntegration shutdown complete');
   309→  }
   310→
   311→  // ─── Private Helpers ─────────────────────────────────────────────────────────
   312→
   313→  private _assertState(expected: IntegrationState, method: string): void {
   314→    if (this._state !== expected) {
   315→      throw new VoiceEngineError(
   316→        `RuntimeIntegration.${method}() called in state '${this._state}'; expected '${expected}'`,
   317→        ErrorCode.PIPELINE_ABORTED,
   318→        false,
   319→        { sessionId: this._sessionId, currentState: this._state, expectedState: expected }
   320→      );
   321→    }
   322→  }
   323→}
   324→

